        {
            List<String> query_list;
            if (My.version_query_list.ContainsKey(version))
            {
                query_list = My.version_query_list[version];
            }
            else
            {
                query_list = new List<string>();

            }
            query_list.Add(query);
            My.version_query_list[version] = query_list;
        }

