                        list.Add(@"CREATE       PROCEDURE sp_update_admission_no_and_Class
 @admissionserialnumber_old       varchar(500) =NULL,
@admissionserialnumber       varchar(500) =NULL,
@Session_id         varchar(500) =NULL,
@updated_by         varchar(500) =NULL,
@updated_date       varchar(500) =NULL,
@session varchar(500) =NULL,
@Class_id varchar(500) =NULL,
@slip_no varchar(500) =NULL,
@rollno_old varchar(500) =NULL,
@Roll_no_New varchar(500) =NULL,
@Class_idnew varchar(500) =NULL,
@Class_name varchar(500) =NULL,
@Old_section varchar(500) =NULL,
@New_Section varchar(500) =NULL,
@status        VARCHAR(5000)
 
AS
Begin 

            ----Insert new data----

            if @status ='updateadmissionno'
             Begin  
        
                 update admission_registor set admissionserialnumber=@admissionserialnumber where admissionserialnumber=@admissionserialnumber_old and Session_id=@Session_id
                 
                 INSERT INTO admission_registor_Change_admission_no_history (Old_admission_no,Current_admission_no,Session_id,Created_By,Date_time,Change_type) values (@admissionserialnumber_old,@admissionserialnumber,@Session_id,@updated_by,@updated_date,'Admission No. Change')
                 
                 update Student_mapping_with_boarding_with_lunch set Admission_no=@admissionserialnumber where Session_id=@Session_id and Admission_no=@admissionserialnumber_old
                 update Admission_fee_collection set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                 update Annual_fee_collection set  Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                 update Discount_Master set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session_id=@Session_id
                 
                 update Discount_Master_for_bus set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session_id=@Session_id
                 
                 update Discount_Master_Monthly_Studentwise set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update Fine_Fees_collection set Admission_no=@admissionserialnumber where  Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update lib_student_transaction_details set student_id=@admissionserialnumber where student_id=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update Monthly_Fee_Collection_Slip set adno=@admissionserialnumber where adno=@admissionserialnumber_old and session=@session
                 
                 update Payment_transaction_process set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update SchoolLedger set Addmission_no=@admissionserialnumber where  Addmission_no=@admissionserialnumber_old and session=@session
                 
                  update Student_Payment_History set Addmission_no=@admissionserialnumber where Addmission_no=@admissionserialnumber_old and Session=@session
                  
                
                 
                 update Typewise_fee_collection set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session=@session
                 
                 ------------------LMS----------
                 update Zoom_Meeting_Joining_Status set User_id=@admissionserialnumber where User_id=@admissionserialnumber_old and Session_id=@Session_id
                 update user_test_total_marks_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and Session_Id=@Session_id
                 
                 update user_test_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and  Session_id=@Session_id
                 update user_test_attempted_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and  Session_id=@Session_id
                 
                 update Subjective_particpation set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_id=@Session_id
                 
                 update Subjective_Pdf_Answer set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                 
                  update Subjective_marks_chart set Studnet_Id=@admissionserialnumber where Studnet_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                  
                  update Subjective_answer set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                  
                   update Subject_Mapping_New set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                   
                   update Student_Remarks_Entry set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id
                   
                   
                   update Student_Practical_Viva_Marks set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id
                   
                   
                   update Student_Attendance_saved_Class_Wise set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
              End
               else  if @status ='updateclass'
                Begin  
                 
                    INSERT INTO Student_Payment_History_Save_bakup (Addmission_no,Session,Date,Idate,Description,Entry_id,Slip_no,Amount,Type,mode,discount,Discoun_in_School,Discoun_in_Hostel,Discoun_in_Transport,fine,is_ofline_sync,Is_online_sync,is_update_in_online,Previous_admission_no,App_Transection_id,time,user_id,Acamedic_Semester_Id,Branch,Class_id,User_Slip_no,Pay_mode_transaction_no,Money_Receipt_Date,Money_Receipt_Idate,Unique_id,Adjust_type,Remarks,Transection_in,insert_time_date,Insert_time_user_id,New_Slip_no)
                    SELECT Addmission_no,Session,Date,Idate,Description,Entry_id,Slip_no,Amount,Type,mode,discount,Discoun_in_School,Discoun_in_Hostel,Discoun_in_Transport,fine,is_ofline_sync,Is_online_sync,is_update_in_online,Previous_admission_no,App_Transection_id,time,user_id,Acamedic_Semester_Id,Branch,Class_id,User_Slip_no,Pay_mode_transaction_no,Money_Receipt_Date,Money_Receipt_Idate,Unique_id,Adjust_type,Remarks,Transection_in,@updated_date,@updated_by,@slip_no
                 FROM Student_Payment_History where Addmission_no=@admissionserialnumber and Session=@session and Class_id=@Class_id
                 
                 
                 update admission_registor set admissionserialnumber=@admissionserialnumber,rollnumber=@Roll_no_New,Section=@New_Section,class=@Class_name,Class_id=@Class_idnew    where admissionserialnumber=@admissionserialnumber_old and Session_id=@Session_id 
                  
                  
                  
                  INSERT INTO admission_registor_Change_admission_no_history (Old_admission_no,Current_admission_no,Session_id,Created_By,Date_time,Change_type,Old_Class_id,Class_Id_New,Roll_no_old,Roll_no_New,Slip_no,Old_Section_name,New_Section) values (@admissionserialnumber_old,@admissionserialnumber,@Session_id,@updated_by,@updated_date,'Class Name Change',@Class_id,@Class_idnew,@rollno_old,@Roll_no_New,@slip_no,@Old_section,@New_Section)
                   
                   
                 ---------------delete from payment history---------------
                 
                 delete from Admission_fee_collection where Admission_no=@admissionserialnumber and session=@session
                 delete from Annual_fee_collection  where Admission_no=@admissionserialnumber and session=@session
                 delete Student_mapping_with_boarding_with_lunch   where Session_id=@Session_id and Admission_no=@admissionserialnumber
                 
                   delete Discount_Master  where admission_no=@admissionserialnumber and session_id=@Session_id
                 
                   delete Discount_Master_for_bus   where admission_no=@admissionserialnumber and session_id=@Session_id
                 
                   delete Discount_Master_Monthly_Studentwise   where Admission_no=@admissionserialnumber and Session_id=@Session_id
                   delete Fine_Fees_collection   where  Admission_no=@admissionserialnumber and Session_id=@Session_id
                   
                    delete Monthly_Fee_Collection_Slip   where adno=@admissionserialnumber and session=@session
                 
                    delete Payment_transaction_process   where Admission_no=@admissionserialnumber and Session_id=@Session_id
                 
                    delete SchoolLedger  where  Addmission_no=@admissionserialnumber and session=@session
                 
                    delete Student_Payment_History  where Addmission_no=@admissionserialnumber and Session=@session
                  
                
                 
                    delete Typewise_fee_collection   where admission_no=@admissionserialnumber and session=@session
                   
                   
                   
                   
                   
                End
    

End");


                        list.Add(@"Alter                   PROCEDURE sp_Graph_Report
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdate int=null,
@todate int=null,
@Storeid      VARCHAR(500)=NULL,
@Session   VARCHAR(500)=NULL,
@Session_id  int=null,
@sp_status       VARCHAR(500)
AS
Begin
    

    ---------Datewise Order Count----------
    if @sp_status ='1'
BEGIN
    select count(id) as total_adm,class from dbo.[admission_registor] t1 where    (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Status='1'   group by t1.class
 END

 ---------Payment History---------
 if @sp_status ='2'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id 
 END
  ---------Dues Payment----------
  if @sp_status ='3'
BEGIN
     select class,isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection] where class_id=admission_registor.Class_id),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise] where class_id=admission_registor.Class_id))),'0') total_amt from dbo.[admission_registor] group by Class_id,class
 END
   ---------Dues/Pais Payment----------
   if @sp_status ='4'
BEGIN
     select * from (select 'Dues' as Status, isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection]),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise]))),'0') total_amt from dbo.[admission_registor]) t group by t.total_amt,t.Status UNION all select * from (select 'Paid' as Status,isnull((select sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 ) t group by t.total_amt,t.Status
 END
 
 
   ---------Dashboard2---------
  ---------Dashboard2 Payment History---------
  if @sp_status ='5'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END

 ---------Dues Payment----------
 if @sp_status ='6'
BEGIN
     select class,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class
 END
  ---------Dues/Paid Payment----------
  if @sp_status ='7'
BEGIN
     select 'Dues' as Status,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class  UNION all select 'Paid' as Status,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END
  ---------Payment paid his----------
  if @sp_status ='8'
BEGIN
     select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id
 END
  ---------Payment History Session Wise---------
  if @sp_status ='9'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id and t1.Session=t2.session where t2.Session_id=@Session_id  group by t2.class,t1.Class_id
 END
  if @sp_status ='10'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id and Session_id=admission_registor.Session_id),0) as total_amt from admission_registor where Session_id=@Session_id group by class,Class_id,Session_id
 END

  if @sp_status ='11'
BEGIN
    select count(id) as total_adm,class from dbo.[admission_registor] t1 where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and Session_id=@Session_id and Status='1' group by t1.class
 END
End");

                        list.Add(@"Alter          PROCEDURE [sp_ReplayHomework]
@Id         int=0,
@Homework_id        varchar(500) =NULL,
@Student_id         varchar(500) =NULL,
@Teacher_id         varchar(500) =NULL,
@Replay         nvarchar(MAX) =NULL,
@Image      varchar(500) =NULL,
@Rplay_id       varchar(500) =NULL,
@Subject_id         varchar(500) =NULL,
@Date       varchar(500) =NULL,
@Idate      varchar(500) =NULL,
@Status         varchar(500) =NULL,
@is_Checked         bit=NULL,
@Class_id       varchar(500) =NULL,
@Section        varchar(500) =NULL,
@Image_sec      varchar(500) =NULL,
@Remark         nvarchar(MAX) =NULL,
@Remark_date        varchar(500) =NULL,
@Remark_Idate       varchar(500) =NULL,
@cmdstatus        VARCHAR(5000)
 
AS
Begin 

            ----Insert new data----

            if @cmdstatus =1-- all student
             Begin  
                 
                 
                 
               --  Select * from Subject_Mapping_New
               Select ar.studentname,ar.admissionserialnumber,ar.rollnumber,ar.Section,ar.session,ar.class as classname,(select top 1 Upload_Date from Homework_Details where Home_Work_id=@Homework_id ) as Upload_Date,(select top 1 CompletingDate from Homework_Details where Home_Work_id=@Homework_id ) as CompletingDate,(select top 1 Date from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as replydate_student,(select top 1 Status from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as Status from admission_registor ar where   ar.Transfer_Status in ('New','NT') and Status='1' and  ar.StudentStatus='AV' and ar.Section=@Section and ar.Class_id=@Class_id and ar.admissionserialnumber in (select Admission_no from Subject_Mapping_New where Class_id=@Class_id and Section=@Section and Sub_id=@Subject_id)  

              End
           
           
           ----Fetching data----
             else if @cmdstatus =2-- when replyed
             Begin  
                 
                 
                 Select ar.studentname,ar.admissionserialnumber,ar.rollnumber,ar.Section,ar.session,ar.class as classname,(select top 1 Upload_Date from Homework_Details where Home_Work_id=@Homework_id ) as Upload_Date,(select top 1 CompletingDate from Homework_Details where Home_Work_id=@Homework_id ) as CompletingDate,(select top 1 Date from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as replydate_student,(select top 1 Status from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as Status from admission_registor ar join ReplayHomework rhw on ar.admissionserialnumber=rhw.Student_id where ar.Status='1' and ar.Section=@Section and ar.Class_id=@Class_id and  rhw.Homework_id=@Homework_id and rhw.Status='Replied' and ar.Transfer_Status in ('New','NT') and  ar.StudentStatus='AV'

              End
             
             
              
 ----Fetching data----
               else if @cmdstatus =3-- when not replyed
             Begin  
                 
                 
                 Select ar.studentname,ar.admissionserialnumber,ar.rollnumber,ar.Section,ar.session,ar.class as classname,(select top 1 Upload_Date from Homework_Details where Home_Work_id=@Homework_id ) as Upload_Date,(select top 1 CompletingDate from Homework_Details where Home_Work_id=@Homework_id ) as CompletingDate,(select top 1 Date from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as replydate_student,(select top 1 Status from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as Status from admission_registor ar where ar.Status='1' and ar.Section=@Section and ar.Class_id=@Class_id and ar.admissionserialnumber not in (select Student_id from ReplayHomework where  Homework_id=@Homework_id) and ar.Transfer_Status in ('New','NT') and  ar.StudentStatus='AV'

              End
          
            
           else if @cmdstatus =4-- when teacher replyed
             Begin  
                 
                 
                 Select ar.studentname,ar.admissionserialnumber,ar.rollnumber,ar.Section,ar.session,ar.class as classname,(select top 1 Upload_Date from Homework_Details where Home_Work_id=@Homework_id ) as Upload_Date,(select top 1 CompletingDate from Homework_Details where Home_Work_id=@Homework_id ) as CompletingDate,(select top 1 Date from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as replydate_student,(select top 1 Status from ReplayHomework where Homework_id=@Homework_id and Student_id=ar.admissionserialnumber) as Status from admission_registor ar join ReplayHomework rhw on ar.admissionserialnumber=rhw.Student_id where ar.Status='1' and ar.Section=@Section and ar.Class_id=@Class_id and  rhw.Homework_id=@Homework_id and rhw.Status='Checked' and ar.Transfer_Status in ('New','NT') and  ar.StudentStatus='AV'

              End
          
          
               else if @cmdstatus =5-- count
             Begin 
             
                 Select count(admissionserialnumber) as total,(Select count(id) from ReplayHomework where Homework_id=@Homework_id and Status='Replied') as replied,(select count(distinct admissionserialnumber) from admission_registor where  StudentStatus='AV' and Transfer_Status in ('New','NT')  and admissionserialnumber not in (select Student_id from ReplayHomework where  Homework_id=@Homework_id) and  Section=@Section and  Class_id=@Class_id) as notreplied,(Select count(id) from ReplayHomework where Homework_id=@Homework_id and Status='Checked') as Checked  from admission_registor ar where ar.Section=@Section and ar.Class_id=@Class_id  and ar.Transfer_Status in ('New','NT') and ar.Status='1' and ar.StudentStatus='AV' and ar.admissionserialnumber in (select Admission_no from Subject_Mapping_New where Class_id=@Class_id and Section=@Section and Sub_id=@Subject_id)  
         end
             
             
             
            

End");


