                        list.Add(@"CREATE  PROCEDURE sp_Fee_collection_report_new
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdate int=null,
@todate int=null,
@Session   VARCHAR(500)=NULL,
@Session_id  int=null,
@class_id  int=null,
@section   VARCHAR(500)=NULL,
@Type   VARCHAR(500)=NULL,
@parameter   VARCHAR(500)=NULL,
@Admission_no  VARCHAR(500)=NULL,
@sp_status       VARCHAR(500)
AS
Begin
    
    

    ---------Collection Datewise PaymentMode---------
 if @sp_status ='1'
BEGIN
    select sum(isnull(convert(float, Amount),0)) as Paid_amt,mode from Student_Payment_History where Type=@Type and Idate>=@fromdate and Idate<=@todate and Session=@Session group by mode
 END

 ---------Headwise fees collection---------
 if @sp_status ='2'
BEGIN
    select DISTINCT Date,Idate from Student_Payment_History where Type=@Type and Idate>=@fromdate and Idate<=@todate and Session=@Session order by Idate asc
 END

  ---------Headwise fees collection---------
  if @sp_status ='3'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate=@fromdate and parameter=@parameter and session=@Session group by feetype,Idate order by feetype asc
 END

  ---------Headwise fees collection---------
  if @sp_status ='4'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate>=@fromdate and Idate<=@todate and parameter=@parameter and session=@Session group by feetype order by feetype asc
 END
 ---------Headwise fees collection Class & Date---------
 if @sp_status ='5'
BEGIN
    select DISTINCT Date,Idate from Student_Payment_History where Type=@Type and Idate>=@fromdate and Idate<=@todate and Session=@Session and class_id=@class_id order by Idate asc
 END
 ---------Headwise fees collection Class & Date & Section---------
 if @sp_status ='6'
BEGIN
    select DISTINCT t1.Date,t1.Idate from Student_Payment_History t1 join admission_registor t2 on t1.Session=t2.Session and t1.Addmission_no=t2.admissionserialnumber and t1.Class_id=t2.Class_id where Type=@Type and t1.Idate>=@fromdate and t1.Idate<=@todate and t1.Session=@Session and t1.class_id=@class_id and t2.Section=@section order by Idate asc
 END
  ---------Headwise fees collection---------
  if @sp_status ='7'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate>=@fromdate and Idate<=@todate and parameter=@parameter and session=@Session and class_id=@class_id group by feetype order by feetype asc
 END
  ---------Headwise fees collection---------
  if @sp_status ='8'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate>=@fromdate and Idate<=@todate and parameter=@parameter and session=@Session and class_id=@class_id and section=@section group by feetype order by feetype asc
 END

  ---------Headwise fees collection---------
  if @sp_status ='9'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate=@fromdate and parameter=@parameter and session=@Session and class_id=@class_id group by feetype,Idate order by feetype asc
 END
  ---------Headwise fees collection---------
  if @sp_status ='10'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate=@fromdate and parameter=@parameter and session=@Session and class_id=@class_id  and section=@section group by feetype,Idate order by feetype asc
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='11'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='New' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='12'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='New' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate and ar.Class_id=@class_id) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='13'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='New' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate and ar.Class_id=@class_id and ar.Section=@section) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='14'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='New' and ar.Status='1'  and ar.Class_id=@class_id and ar.admissionserialnumber=@Admission_no) t where Payable_amount>'0'
 END

  




---------Admission Fee Student Wise collection---------
  if @sp_status ='24'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Annual_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='NT' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='25'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Annual_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='NT' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate and ar.Class_id=@class_id) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='26'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Annual_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='NT' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate and ar.Class_id=@class_id and ar.Section=@section) t where Payable_amount>'0'
 END
---------Admission Fee Student Wise collection---------
  if @sp_status ='27'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Annual_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='NT' and ar.Status='1'  and ar.Class_id=@class_id and ar.admissionserialnumber=@Admission_no) t where Payable_amount>'0'
 END

---------Collection Datewise Payment---------
    if @sp_status ='28'
BEGIN
    select DISTINCT feetype,content_id from Typewise_fee_collection where parameter=@parameter and Idate>=@fromdate and Idate<=@todate and session=@session order by feetype asc
 END
---------Collection Datewise Payment---------
