                        list.Add(@"Alter   PROCEDURE sp_Fetch_month_dues 
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id as int,
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50)='no',
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@transportportation_id  as varchar(50),
@sp_status       VARCHAR(500)
AS
Begin
    ---------Datewise Order Count----------
    if @sp_status ='1'
BEGIN
    select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter='MonthlyFee' and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all
select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@admission_no and tr.Month=@months

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id) t 
 END

End");

                        list.Add(@"Alter       proc sp_fetch_monthly_fee
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id as int,
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50)='no',
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@transportportation_id  as varchar(50)
as 
begin 
    declare @applyfor as varchar(50),@parameter as varchar(50);
  
        if @hosteltaken='yes'
            begin
                 set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
             select '0'id,@admission_no admission_no,@class class,@session session,parameter,content,amount,'0',amount,'Dues',@months months,content_id,Ledger,0,0,0,disc_amount from (  select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months union all select 'TransportationFee' as content,tr.parameter_id as content_id,tr.Amount as amount,@parameter parameter,tr.Ledger,'0' disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@Admission_No and tr.Month=@months union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id  union all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and Hostel_id= case when Apply_for='Both' then 0 else @hostel_id end  and ( Apply_for=@applyfor or Apply_for='Both'))t;
                 
            end 
         else
            begin
                set @applyfor='Day Scholar';
                 set @parameter='MonthlyFee'; 
                 --set @parameter_id='4'; 
                 select '0'id, @admission_no admission_no,@class class,@session session,parameter,content,amount,'0',amount,'Dues',@months months,content_id,Ledger,0,0,0,disc_amount from ( 
                 
                 select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months and fmc.parameter_id=@parameter_id union all select 'TransportationFee' as content,tr.parameter_id as content_id,tr.Amount as amount,@parameter parameter,tr.Ledger,
                
                
                (isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount
                
                
                
                from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@Admission_No and tr.Month=@months union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id union all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null))t;
          end
end");

