                #region Case 1.0.0.33
                case "1.0.0.33":
                    {
                        list.Add(@"Alter              PROCEDURE sp_Payroll_Graph_Report
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdateV           int=NULL,
@fromdate int=null,
@todate int=null,
@Storeid      VARCHAR(500)=NULL,
@Genders      VARCHAR(500)=NULL,
@year    VARCHAR(500)=NULL,
@Department_id  VARCHAR(500)=NULL,
@sp_status       VARCHAR(500) 
AS
Begin
    

---------Datewise Order Count----------
    if @sp_status ='1'
    BEGIN 
        select format(DateTime, 'dd/MM/yyyy') as apdate,count(distinct Employee_id) present_total from dbo.[PRL_Attendance_Log] where Format(convert(DateTime,DateTime,103), 'yyyyMMdd')>=@fromdate  group by  format(DateTime, 'dd/MM/yyyy') 
 END
 
 if @sp_status ='2'
BEGIN
    select (select top 1 name from PRL_Designation_Master where description_id=PRL_Employee_Master.Designation_id) as Design_name,count(id) as No_of_emp from PRL_Employee_Master  group by Designation_id
 END

 if @sp_status ='3'
BEGIN
    select (select top 1 name from PRL_Designation_Master where description_id=PRL_Employee_Master.Designation_id) as Design_name,count(id) as No_of_emp from PRL_Employee_Master where Gender=@Genders group by Designation_id
 END
 if @sp_status ='4'
BEGIN
    select (select top 1 name from PRL_Department_Master where department_id=PRL_Employee_Master.Department_id) as Dep_name,count(id) as No_of_emp from PRL_Employee_Master group by Department_id
 END
if @sp_status ='5'
BEGIN
    select (select top 1 name from PRL_Department_Master where department_id=PRL_Employee_Master.Department_id) as Dep_name,count(id) as No_of_emp from PRL_Employee_Master where Gender=@Genders group by Department_id
 END
if @sp_status ='6'
BEGIN
    select (select top 1 grade_name from PRL_Grade_Master where grade_id=PRL_Employee_Master.Grade_id) as grade_name,count(id) as No_of_emp from PRL_Employee_Master group by Grade_id
 END
if @sp_status ='7'
BEGIN
    select Religion,count(id) as No_of_emp from PRL_Employee_Master group by Religion
 END
if @sp_status ='8'
BEGIN
   select 'Present' as AttType,count(distinct Employee_id) TypeCount  from(  select *,( select count(Employee_id) from dbo.[PRL_Attendance_Log] where Employee_id=PRL_Employee_Master.Emp_Code and format(DateTime,'yyyyMMdd')=@Sidate) atten from dbo.[PRL_Employee_Master]  )t where atten>0
 union all
select distinct 'Absent' as AttType, (case when cast(absent as float)=0 then 0 else (cast(absent as float)-cast(leave as float)) end ) absent from ( select (select count(distinct Employee_id)  from(  select *,( select count(Employee_id) from dbo.[PRL_Attendance_Log] where Employee_id=PRL_Employee_Master.Emp_Code and format(DateTime,'yyyyMMdd')=@Sidate) atten from dbo.[PRL_Employee_Master]  )t where atten=0) as absent,(select count(Employee_Id) leave_total from dbo.[PRL_Emp_Date_wise_leave_entry] where idate=@Sidate) as leave from  PRL_Employee_Master where Status='Active')t
union all
select 'Leave' as AttType,count(Employee_Id) TypeCount from dbo.[PRL_Emp_Date_wise_leave_entry] where idate=@Sidate
 

 END
if @sp_status ='9'
BEGIN
    select (select top 1 name from PRL_Department_Master where department_id=t2.Department_id) as Dep_name, count(t1.Employee_id) as TypeCount from dbo.[PRL_Employee_Daily_attendance_chart] t1 join PRL_Employee_Master t2 on t1.Employee_id=t2.Employee_id where idate=@Sdate and isnull(Shift_1_Working,0)+isnull(Shift_2_Working,0)>='3' GROUP by t2.Department_id
 END
if @sp_status ='10'
BEGIN
    select (select top 1 grade_name from PRL_Grade_Master where grade_id=t2.Grade_id) as grade_name, count(t1.Employee_id) as TypeCount from dbo.[PRL_Employee_Daily_attendance_chart] t1 join PRL_Employee_Master t2 on t1.Employee_id=t2.Employee_id where idate=@Sdate and isnull(Shift_1_Working,0)+isnull(Shift_2_Working,0)>='3' GROUP by t2.Grade_id
 END
if @sp_status ='11'
BEGIN
    select month,sum(convert(float, Net_Salary)) as Total_salary from PRL_Employee_Salary_chart where year=@year GROUP by month order by month asc
 END
if @sp_status ='12'
BEGIN
    select month,sum(convert(float, Net_Salary)) as Total_salary from PRL_Employee_Salary_chart t1 join PRL_Employee_Master t2 on t1.Employee_id=t2.Employee_id where year=@year and Department_id=@Department_id GROUP by month order by month asc
 END

if @sp_status ='13'
BEGIN
    select month,sum(convert(float, com_PF)) as Total_Pf from PRL_Employee_Salary_chart t1 join PRL_Employee_Master t2 on t1.Employee_id=t2.Employee_id where year=@year GROUP by month order by month asc
 END
if @sp_status ='14'
BEGIN
    select month,sum(convert(float, com_ESI)) as Total_Esi from PRL_Employee_Salary_chart t1 join PRL_Employee_Master t2 on t1.Employee_id=t2.Employee_id where year=@year GROUP by month order by month asc
 END
End");




