                        list.Add(@"drop PROCEDURE [dbo].[sp_sync_attendance_list]");
                        list.Add(@"drop [dbo].[attendance_list]");

                        list.Add(@"create TYPE [dbo].[attendance_list] AS TABLE(  
    [Employee_id] varchar(500),
