                        list.Add(@"Alter                 proc sp_Fee_Collection_Report
@session_id as int=0,
@session as  varchar(50)=null,
@classid as int=0,
@typestatus as int=1,--typestatus=1(Old Payment system) typestatus=2(New Payment system)
@Idate as  int=0,
@feetpe as varchar(50)=null
 
as 
begin 
    if @typestatus = 1-- old payment system
    begin
        if(@feetpe=0)--total dues
        begin
            select sum(cast(totaldues as float)-cast(paid as float))  from(select  admissionserialnumber,studentname,session,class,(select (classfee-isnull(discount,0)) netfee from (select sum (cast(amount as  float)) as classfee, (isnull((select sum(cast( disc_amount as float)) from dbo.[Discount_Master] where admission_no=ad.admissionserialnumber and session=ad.session and category_id=ad.Category_id and sub_category_id=ad.SubCategory_id),(select sum(cast( disc_amount as float)) from dbo.[Discount_Master] where Class_id=ad.Class_id and admission_no='All' and session=ad.session  and category_id=ad.Category_id and sub_category_id=ad.SubCategory_id))) as discount    from dbo.[Fee_master_content_wise] where class_id=ad.Class_id and session_id=ad.Session_id)t) as totaldues ,( Select  sum(cast(Amount as float)) totalpaid from Student_Payment_History where Addmission_no=ad.admissionserialnumber and session=ad.session and Class_id=ad.Class_id) as paid  from dbo.[admission_registor] ad where ad.Class_id=@classid and ad.Session_id=@session_id)p
         End
        
         else if(@feetpe=1)--totalpayment
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session 
         End
            else if(@feetpe=2)--totaladmissionfeee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Type='Admission'
         End
          else if(@feetpe=3)--totalreadmission
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Type='Readmission'
         End
        
        else if(@feetpe=4)--head wise collection
        begin
            select  sum(cast (paid as float )) as amount1,Content from dbo.[Monthly_Fee_Collection_Slip] where  class=@classid and Session=@session  group by Content
         End
        
        -------------------------Today summery-----------------------------
        else if(@feetpe=5)--totalpayment
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Idate=@Idate
         End
        else if(@feetpe=6)--totaladmissionfeee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Type='Admission' and Idate=@Idate
         End
        
        else if(@feetpe=7)--totalreadmission
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Type='Readmission' and Idate=@Idate
         End
        
        else if(@feetpe=8)--head wise collection
        begin
            select  sum(cast (mfcs.paid as float )) as amount1,mfcs.Content from dbo.[Monthly_Fee_Collection_Slip] mfcs join Student_Payment_History sph on mfcs.slipno=sph.Slip_no where  mfcs.class=@classid and mfcs.Session=@session and sph.Idate=@Idate  group by mfcs.Content
         End
        
        
         else if(@feetpe=9)--totaladmissionfeee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Type='Admission' and Idate=@Idate
         End
        
        else if(@feetpe=10)--totalreadmission
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Type='Readmission' and Idate=@Idate
         End
         else if(@feetpe=11)--head wise collection
        begin
            select  sum(cast (mfcs.paid as float )) as amount1,mfcs.Content from dbo.[Monthly_Fee_Collection_Slip] mfcs join Student_Payment_History sph on mfcs.slipno=sph.Slip_no where sph.Idate=@Idate  group by mfcs.Content
         End
        
         else if(@feetpe=12)--payment head wise 
        begin
            select  sum(cast (Amount as float )) as amount1,mode from dbo.[Student_Payment_History] where   Idate=@Idate  group by mode
         End
        
        else if(@feetpe=13)--totalmonthely
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Type='Monthly' and Idate=@Idate
         End
        
         else if(@feetpe=14)--total class and session  wise month fee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Type='Monthly' and Idate=@Idate
         End
        else if(@feetpe=15)--total class and session  wise month fee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Class_id=@classid and Session=@session and Type='Monthly' 
         End
        
    end
    
    
    if @typestatus = 2-- old payment system
    begin
        
        if(@feetpe=0)--total dues
        begin
            select sum(cast(totaldues as float)-cast(paid as float))  from(select  admissionserialnumber,studentname,session,class,(select (classfee-isnull(discount,0)) netfee from (select sum (cast(amount as  float)) as classfee, (isnull((select sum(cast( disc_amount as float)) from dbo.[Discount_Master] where admission_no=ad.admissionserialnumber and session=ad.session and category_id=ad.Category_id and sub_category_id=ad.SubCategory_id),(select sum(cast( disc_amount as float)) from dbo.[Discount_Master] where Class_id=ad.Class_id and admission_no='All' and session=ad.session  and category_id=ad.Category_id and sub_category_id=ad.SubCategory_id))) as discount    from dbo.[Fee_master_content_wise] where class_id=ad.Class_id and session_id=ad.Session_id)t) as totaldues ,( Select  sum(cast(Amount as float)) totalpaid from Student_Payment_History where Addmission_no=ad.admissionserialnumber and session=ad.session and Class_id=ad.Class_id) as paid  from dbo.[admission_registor] ad where    ad.Session_id=@session_id)p
         End
        
         else if(@feetpe=1)--totalpayment
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where  Session=@session 
         End
            else if(@feetpe=2)--totaladmissionfeee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where   Session=@session and Type='Admission'
         End
          else if(@feetpe=3)--totalreadmission
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where  Session=@session and Type='Readmission'
         End
        
        else if(@feetpe=4)--head wise collection
        begin
            select  sum(cast (paid as float )) as amount1,Content from dbo.[Monthly_Fee_Collection_Slip] where   Session=@session  group by Content
         End
        
        -------------------------Today summery-----------------------------
        else if(@feetpe=5)--totalpayment
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where  Session=@session and Idate=@Idate
         End
        else if(@feetpe=6)--totaladmissionfeee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where  Session=@session and Type='Admission' and Idate=@Idate
         End
        
        else if(@feetpe=7)--totalreadmission
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where   Session=@session and Type='Readmission' and Idate=@Idate
         End
        
        else if(@feetpe=8)--head wise collection
        begin
            select  sum(cast (mfcs.paid as float )) as amount1,mfcs.Content from dbo.[Monthly_Fee_Collection_Slip] mfcs join Student_Payment_History sph on mfcs.slipno=sph.Slip_no where   mfcs.Session=@session and sph.Idate=@Idate  group by mfcs.Content
         End
        
        
         else if(@feetpe=9)--totaladmissionfeee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Type='Admission' and Idate=@Idate
         End
        
        else if(@feetpe=10)--totalreadmission
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Type='Readmission' and Idate=@Idate
         End
         else if(@feetpe=11)--head wise collection
        begin
            select  sum(cast (mfcs.paid as float )) as amount1,mfcs.Content from dbo.[Monthly_Fee_Collection_Slip] mfcs join Student_Payment_History sph on mfcs.slipno=sph.Slip_no where sph.Idate=@Idate  group by mfcs.Content
         End
        
         else if(@feetpe=12)--payment head wise 
        begin
            select  sum(cast (Amount as float )) as amount1,mode from dbo.[Student_Payment_History] where   Idate=@Idate  group by mode
         End
        
        else if(@feetpe=13)--totalmonthely
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where Type='Monthly' and Idate=@Idate
         End
        
         else if(@feetpe=14)--total class and session  wise month fee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where  Session=@session and Type='Monthly' and Idate=@Idate
         End
        else if(@feetpe=15)--total class and session  wise month fee
        begin
            select  sum(cast(Amount as float)) totalpaid from dbo.[Student_Payment_History] where   Session=@session and Type='Monthly' 
         End
    end
    
    
end");

                        list.Add(@"Alter     PROCEDURE sp_Fetch_month_dues 
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id as int,
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50)='no',
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@transportportation_id  as varchar(50),
@sp_status       VARCHAR(500)
AS
Begin
    ---------Datewise Order Count----------
    
    if @hosteltaken='yes'
    
            begin
                 if @sp_status ='1'
BEGIN
    declare @applyfor as varchar(50),@parameter as varchar(50);
    set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
    
                 select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all
select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@admission_no and tr.Month=@months

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id) t 
 END 
                 
            end 
         else
            begin
                
    if @sp_status ='1'
BEGIN
    select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter='MonthlyFee' and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all
select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@admission_no and tr.Month=@months

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id) t 
 END
 end 
End");

                        list.Add(@"Alter      PROCEDURE sp_Graph_Report
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdate int=null,
@todate int=null,
@Storeid      VARCHAR(500)=NULL,
@Session   VARCHAR(500)=NULL,
@Session_id  int=null,
@sp_status       VARCHAR(500)
AS
Begin
    

    ---------Datewise Order Count----------
    if @sp_status ='1'
BEGIN
    -- select count(id) as total_adm,class from dbo.[admission_registor] t1 where    (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Status='1'   group by t1.class
    
       select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV'   and t1.Status='1' group by t1.class,cm.Position order by cm.Position
 END

 ---------Payment History---------
 if @sp_status ='2'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id 
 END
  ---------Dues Payment----------
  if @sp_status ='3'
BEGIN
     select class,isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection] where class_id=admission_registor.Class_id),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise] where class_id=admission_registor.Class_id))),'0') total_amt from dbo.[admission_registor] group by Class_id,class
 END
   ---------Dues/Pais Payment----------
   if @sp_status ='4'
BEGIN
     select * from (select 'Dues' as Status, isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection]),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise]))),'0') total_amt from dbo.[admission_registor]) t group by t.total_amt,t.Status UNION all select * from (select 'Paid' as Status,isnull((select sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 ) t group by t.total_amt,t.Status
 END
 
 
   ---------Dashboard2---------
  ---------Dashboard2 Payment History---------
  if @sp_status ='5'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END

 ---------Dues Payment----------
 if @sp_status ='6'
BEGIN
     select class,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class
 END
  ---------Dues/Paid Payment----------
  if @sp_status ='7'
BEGIN
     select 'Dues' as Status,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class  UNION all select 'Paid' as Status,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END
  ---------Payment paid his----------
  if @sp_status ='8'
BEGIN
     select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id
 END
  ---------Payment History Session Wise---------
  if @sp_status ='9'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id and t1.Session=t2.session where t2.Session_id=@Session_id  group by t2.class,t1.Class_id
 END
  if @sp_status ='10'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id and Session_id=admission_registor.Session_id),0) as total_amt from admission_registor where Session_id=@Session_id group by class,Class_id,Session_id
 END

  if @sp_status ='11'
BEGIN
    select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Session_id=@Session_id and t1.Status='1' group by t1.class,cm.Position order by cm.Position
 END
  if @sp_status ='12'
BEGIN
    select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Session_id=@Session_id and t1.Status='1' and hosteltaken='Yes' group by t1.class,cm.Position order by cm.Position
 END
End");



