                        list.Add(@"CREATE   PROCEDURE sp_Fee_collection_day_end_report
@fromdate int=null,
@todate int=null,
@Type   VARCHAR(500)=NULL,
@Session   VARCHAR(500)=NULL,
@Session_id   VARCHAR(500)=NULL,
@Paymentmode   VARCHAR(500)=NULL,
@userid   VARCHAR(500)=NULL,
@sp_status        VARCHAR(5000)
 
AS
Begin 

    
   
    if @sp_status ='1'--- day boarding school hostler
    BEGIN
        
         if @Paymentmode ='Cash'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ar.Session_id =@Session_id and  ad.parameter_New=@Type  and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by Idate asc
    END
    ELSE
    BEGIN
        select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ar.Session_id =@Session_id and  ad.parameter_New=@Type  and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' order by Idate asc
       
     END

        
    END 
  else if @sp_status ='2'--- form seal
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no from Form_sale_details      where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' order by idate asc
    END
    ELSE
    BEGIN
        select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no from Form_sale_details      where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' order by idate asc
       
     END
        
    End

else if @sp_status ='3'--- other fee
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' order by ad.Payment_Idate asc
    END
    ELSE
    BEGIN
        select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' order by ad.Payment_Idate asc
       
     END
        
    End


   else if @sp_status ='4'---  over all summery
   BEGIN
       
       
       Select sum(cast(Amount as float )) as Amount,parameter_New from Student_Payment_History where  parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and   Session =@Session and   Idate>=@fromdate and  Idate<=@todate group by parameter_New union all Select sum(cast(Amount as float )) as Amount,'Form Sale'parameter_New from Form_sale_details where     session =@Session and   Idate>=@fromdate and  Idate<=@todate union all Select sum(cast(Content_Fee as float )) as Amount,'Other Fee'parameter_New from Other_Fee_Taken_For_Student where    Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate
   
        
    End
   
   
    else if @sp_status ='5'---  user wise collection report
   BEGIN
   
       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id =@Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate and  ad.user_id=@userid   UNION all   select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master  on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode   where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate and user_id=@userid UNION all 
       select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Created_by=@userid  order by mode,Idate 
   
End
   else if @sp_status ='6'---  All user wise collection report
   BEGIN
   
       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id =@Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate     UNION all   select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master  on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode   where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate     UNION all 
       select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate  order by mode,Idate 
   
End


End");
                        list.Add(@"Alter       PROCEDURE sp_Fee_collection_day_end_report
@fromdate int=null,
@todate int=null,
@Type   VARCHAR(500)=NULL,
@Session   VARCHAR(500)=NULL,
@Session_id   VARCHAR(500)=NULL,
@Paymentmode   VARCHAR(500)=NULL,
@userid   VARCHAR(500)=NULL,
@Financial_year   VARCHAR(500)=NULL,
@sp_status        VARCHAR(5000)
 
AS
Begin 

    
   
    if @sp_status ='1'--- day boarding school hostler
    BEGIN
        
         if @Paymentmode ='Cash'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ar.Session_id =@Session_id and  ad.parameter_New=@Type  and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by Idate asc
    END
    ELSE
    BEGIN
        select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ar.Session_id =@Session_id and  ad.parameter_New=@Type  and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' order by Idate asc
       
     END

        
    END 
  else if @sp_status ='2'--- form seal
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no from Form_sale_details      where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' order by idate asc
    END
    ELSE
    BEGIN
        select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no from Form_sale_details      where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' order by idate asc
       
     END
        
    End

else if @sp_status ='3'--- other fee
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' order by ad.Payment_Idate asc
    END
    ELSE
    BEGIN
        select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' order by ad.Payment_Idate asc
       
     END
        
    End


   else if @sp_status ='4'---  over all summery
   BEGIN
       
       
       select * from (Select sum(cast(Amount as float )) as Amount,parameter_New from Student_Payment_History where  parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and   Session =@Session and   Idate>=@fromdate and  Idate<=@todate group by parameter_New union all Select sum(cast(Amount as float )) as Amount,'Form Sale'parameter_New from Form_sale_details where     session =@Session and   Idate>=@fromdate and  Idate<=@todate union all Select sum(cast(Content_Fee as float )) as Amount,'Other Fee'parameter_New from Other_Fee_Taken_For_Student where    Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate) t where Amount>0
   
        
    End
   
   
    else if @sp_status ='5'---  user wise collection report
   BEGIN
   
       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id =@Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate and  ad.user_id=@userid   UNION all   select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master  on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode   where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate and user_id=@userid UNION all 
       select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Created_by=@userid  order by mode,Idate 
   
End
   else if @sp_status ='6'---  All user wise collection report
   BEGIN
   
       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id =@Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate     UNION all   select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master  on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode   where  session =@Session  and  Idate>=@fromdate and  Idate<=@todate     UNION all 
       select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate  order by mode,Idate 
   
End
   else if @sp_status ='7'---  General Expenses
   BEGIN
       select *,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id=Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name  from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode='Cash' and Financial_year=@Financial_year order by Id desc 
End
      else if @sp_status ='8'---  General Expenses
   BEGIN
       select *,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id=Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name  from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode!='Cash' and Financial_year=@Financial_year order by Id desc 
End
   else if @sp_status ='9'---  Overall Amount Collection
   BEGIN
       select * from (select *,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from (Select isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New=j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and   Session =@Session and   Idate>=@fromdate and  Idate<=@todate and mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New=j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and   Session =@Session and   Idate>=@fromdate and  Idate<=@todate and mode!='Cash'),0) as AmountOnline,parameter_New from Student_Payment_History j where  parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and   Session =@Session and   Idate>=@fromdate and  Idate<=@todate group by j.parameter_New
UNION all

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where session=@Session and   Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Form_sale_details where session=@Session and   Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash'),0) as AmountOnline,'Form Sale'parameter_New from Form_sale_details where  session=@Session and   Idate>=@fromdate and  Idate<=@todate
UNION all

Select top 1 isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Other Fee' parameter_New from Other_Fee_Taken_For_Student where Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate) t)j where ttl_amount>0
End

 else if @sp_status ='10'---  General Expenses Total
   BEGIN
       select *,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from (Select isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Financial_year =@Session_id and   Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Financial_year =@Session_id and   Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Expenses' parameter_New from Vendor_general_expense where Financial_year =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate)t
End

End");
