                        list.Add(@"Alter               PROCEDURE sp_Graph_Report
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdate int=null,
@todate int=null,
@Storeid      VARCHAR(500)=NULL,
@Session   VARCHAR(500)=NULL,
@Session_id  int=null,
@Class_id  VARCHAR(500)=NULL,
@Class_name  VARCHAR(500)=NULL,
@Parameter  VARCHAR(500)=NULL,
@MonthPosition  int=null,
@fromIdate  int=null,
@toIdate  int=null,
@MonthName  VARCHAR(500)=NULL,
@PrevMonthName  VARCHAR(500)=NULL,
@sp_status       VARCHAR(500)
AS
Begin
    

    ---------Datewise Order Count----------
    if @sp_status ='1'
BEGIN
    -- select count(id) as total_adm,class from dbo.[admission_registor] t1 where    (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Status='1'   group by t1.class
    
       select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV'   and t1.Status='1' group by t1.class,cm.Position order by cm.Position
 END

 ---------Payment History---------
 if @sp_status ='2'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id 
 END
  ---------Dues Payment----------
  if @sp_status ='3'
BEGIN
     select class,isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection] where class_id=admission_registor.Class_id),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise] where class_id=admission_registor.Class_id))),'0') total_amt from dbo.[admission_registor] group by Class_id,class
 END
   ---------Dues/Pais Payment----------
   if @sp_status ='4'
BEGIN
     select * from (select 'Dues' as Status, isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection]),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise]))),'0') total_amt from dbo.[admission_registor]) t group by t.total_amt,t.Status UNION all select * from (select 'Paid' as Status,isnull((select sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 ) t group by t.total_amt,t.Status
 END
 
 
   ---------Dashboard2---------
  ---------Dashboard2 Payment History---------
  if @sp_status ='5'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END

 ---------Dues Payment----------
 if @sp_status ='6'
BEGIN
     select class,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class
 END
  ---------Dues/Paid Payment----------
  if @sp_status ='7'
BEGIN
     select 'Dues' as Status,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class  UNION all select 'Paid' as Status,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END
  ---------Payment paid his----------
  if @sp_status ='8'
BEGIN
     select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id
 END
  ---------Payment History Session Wise---------
  if @sp_status ='9'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id and t1.Session=t2.session where t2.Session_id=@Session_id  group by t2.class,t1.Class_id
 END
  if @sp_status ='10'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id and Session_id=admission_registor.Session_id),0) as total_amt from admission_registor where Session_id=@Session_id group by class,Class_id,Session_id
 END

  if @sp_status ='11'
BEGIN
    select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Session_id=@Session_id and t1.Status='1' group by t1.class,cm.Position order by cm.Position
 END
  if @sp_status ='12'
BEGIN
    select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Session_id=@Session_id and t1.Status='1' and hosteltaken='Yes' group by t1.class,cm.Position order by cm.Position
 END

  if @sp_status ='13'
BEGIN
    select t1.Month,isnull(sum(convert(float, paid)),0) as Total,t2.Position from Monthly_Fee_Collection_Slip t1 join Month_Index t2 on t1.Month=t2.Month where session='2022-2023' and  parameter='MonthlyFee' group by t1.Month,t2.Position order by t2.Position asc
 END
if @sp_status ='14'
BEGIN
    select t1.Month,isnull(sum(convert(float, paid)),0) as Total,t2.Position from Monthly_Fee_Collection_Slip t1 join Month_Index t2 on t1.Month=t2.Month where session='2022-2023' and  parameter='MonthlyFee' and t1.class=@Class_id group by t1.Month,t2.Position order by t2.Position asc
 END

if @sp_status ='15'
BEGIN
    select Month_name,(convert(float, Estimated_collection)+convert(float, Total_late_fine)) as [Estimated Collection],Total_collected as [Total Collected],(convert(float, Estimated_collection)-convert(float, Total_collected)) as [Total Dues]  from (select t1.Month_name,isnull(sum(convert(float, Payable_amounts)),0) as Estimated_collection,(select isnull(sum(convert(float, paid)),0) from Monthly_Fee_Collection_Slip where Month=t1.Month_name and session=@Session and  parameter=@Parameter) as Total_collected,(select isnull(sum(convert(float, paid)),0) from Monthly_Fee_Collection_Slip where Month=t1.Month_name and session=@Session and  parameter=@Parameter and Content='Late Fine') as Total_late_fine,t2.Position from Temp_typewise_estimated_fee t1 join Month_Index t2 on t1.Month_name=t2.Month where Session_id=@Session_id and  Parameter=@Parameter and Fee_head_type!='Late Fine' and t2.Position<=@MonthPosition group by t1.Month_name,t2.Position) t order by Position asc
 END
if @sp_status ='16'    ----  ALL CLASS FIRST MONTH
BEGIN
    select Month_name,(convert(float, Estimated_collection)+convert(float, Total_late_fine)+convert(float, Adv_collected)) as [Estimated Collection],Total_collected as [Total Collected],((convert(float, Estimated_collection)+convert(float, Adv_collected))-convert(float, Total_collected)) as [Total Dues]  from (select t1.Month_name,isnull(sum(convert(float, Payable_amounts)),0) as Estimated_collection,(select isnull(sum(convert(float, paid)),0) from Monthly_Fee_Collection_Slip where Idate<=@toIdate and session=@Session and  parameter=@Parameter) as Total_collected,(select isnull(sum(convert(float, paid)),0) from Monthly_Fee_Collection_Slip where Month=t1.Month_name and session=@Session and  parameter=@Parameter and Content='Late Fine') as Total_late_fine,t2.Position,(select isnull(sum(convert(float, paid)),0) from Monthly_Fee_Collection_Slip where Idate<=@toIdate and session=@Session and  parameter=@Parameter) as Adv_collected from Temp_typewise_estimated_fee t1 join Month_Index t2 on t1.Month_name=t2.Month where Session_id=@Session_id and  Parameter=@Parameter and Fee_head_type!='Late Fine' and t2.Month=@MonthName  group by t1.Month_name,t2.Position) t order by Position asc
 END
if @sp_status ='17' ----  ALL CLASS AFTER FIRST MONTH
BEGIN
