                        list.Add(@"Alter               proc sp_fetch_monthly_fee
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id as int,
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50)='no',
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@monthid  as int=0,
@transportportation_id  as varchar(50)
as 
begin 
    declare @applyfor as varchar(50),@parameter as varchar(50);
  
        if @hosteltaken='yes'
            begin
                 set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
             select '0'id,@admission_no admission_no,@class class,@session session,parameter,content,amount,'0',amount,'Dues',@months months,content_id,Ledger,0,0,0,disc_amount from (  select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months union all select 'TransportationFee' as content,tr.parameter_id as content_id,tr.Amount as amount,@parameter parameter,tr.Ledger,'0' disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@Admission_No and tr.Month=@months union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id  union all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and Hostel_id= case when Apply_for='Both' then 0 else @hostel_id end  and ( Apply_for=@applyfor or Apply_for='Both'))t;
                 
            end 
         else
            begin
                set @applyfor='Day Scholar';
                 set @parameter='MonthlyFee'; 
                 --set @parameter_id='4'; 
                 select '0'id, @admission_no admission_no,@class class,@session session,parameter,content,amount,'0',amount,'Dues',@months months,content_id,Ledger,0,0,0,disc_amount from ( 
                 
                 select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months and fmc.parameter_id=@parameter_id 
                 
                 union all select 'TransportationFee' as content,tr.parameter_id as content_id,tr.Amount as amount,@parameter parameter,tr.Ledger, (isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount
                 from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@Admission_No and tr.Month=@months  and tr.Session=@session  join Student_mapping_with_TransportPath smt on  ar.Session_id=smt.Session_id and ar.admissionserialnumber=smt.Admission_no and smt.Year_month<=@monthid 
                 
                 union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id 
                 
                 union all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null))t;
          end
end");
                        list.Add(@"Alter            PROCEDURE sp_Fee_collection_day_end_report
@fromdate int = null,
@todate int = null,
@Type   VARCHAR(500) = NULL,
@Session   VARCHAR(500) = NULL,
@Session_id   VARCHAR(500) = NULL,
@Paymentmode   VARCHAR(500) = NULL,
@userid   VARCHAR(500) = NULL,
@Financial_year   VARCHAR(500) = NULL,
@sp_status        VARCHAR(5000)


AS
Begin




    if @sp_status = '1'-- - day boarding school hostler
      BEGIN


         if @Paymentmode = 'Cash'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by Idate asc
   END
    ELSE
    BEGIN
        select ar.Session_id, ar.dateofadmission, ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' order by Idate asc


     END


    END 
  else if @sp_status ='2'--- form seal
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=Form_sale_details.user_id) as User_name from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' order by idate asc
    END
    ELSE
    BEGIN
        select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=Form_sale_details.user_id) as User_name from Form_sale_details where  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' order by idate asc


     END

    End

else if @sp_status ='3'--- other fee
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' order by ad.Payment_Idate asc
    END
    ELSE
    BEGIN
        select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' order by ad.Payment_Idate asc


     END

    End


   else if @sp_status ='4'---  over all summery
   BEGIN 
       select* from(Select sum(cast(Amount as float )) as Amount,parameter_New from Student_Payment_History where  parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Session = @Session and Idate>=@fromdate and  Idate<=@todate group by parameter_New union all Select sum(cast(Amount as float )) as Amount,'Form Sale'parameter_New from Form_sale_details where     session =@Session and   Idate>=@fromdate and  Idate<=@todate union all Select sum(cast(Content_Fee as float )) as Amount,'Other Fee'parameter_New from Other_Fee_Taken_For_Student where    Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate) t where Amount>0
   
        
    End
   
   
    else if @sp_status ='5'---  user wise collection report
   BEGIN

       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id = @Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate and  ad.user_id= @userid   UNION all   select Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode where  session =@Session and  Idate>=@fromdate and  Idate<=@todate and user_id=@userid UNION all
    select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Created_by=@userid order by mode, Idate


End
   else if @sp_status ='6'---  All user wise collection report
   BEGIN


       select ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id = @Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate UNION all select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode where  session =@Session and  Idate>=@fromdate and  Idate<=@todate UNION all
select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate order by mode, Idate


End
   else if @sp_status ='7'---  General Expenses
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode='Cash' order by Id desc
End
      else if @sp_status ='8'---  General Expenses
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode!='Cash'  order by Id desc
End
   else if @sp_status ='9'---  Overall Amount Collection
   BEGIN
       select * from(select *, (cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cash' and Session=j.Session),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and Session=j.Session),0) as AmountOnline,parameter_New,Session from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate group by j.parameter_New,j.Session

UNION all
Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' and Session=j.Session),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' and Session=j.Session),0) as AmountOnline,'Form Sale' as parameter_New, Session  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate group by Session

UNION all
Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' and Session_id=j.Session_id),0) as AmountCash,isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' and Session_id=j.Session_id),0) as AmountOnline,'Other Fee' as parameter_New, k.Session  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate group by k.Session,j.Session_id) t)j where ttl_amount>0
End

 else if @sp_status ='10'---  General Expenses Total
   BEGIN
       select*,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Financial_year = @Session_id and Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Financial_year = @Session_id and Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Expenses' parameter_New from Vendor_general_expense where Financial_year =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate)t UNION all select *,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Amount as float )) from General_expense where Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Expenses' parameter_New from General_expense where Idate>=@fromdate and  Idate<=@todate)t
End
   
    else if @sp_status ='11'---  General Expenses Without Vendor
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name,(select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode='Cash' order by Id desc
End
   else if @sp_status ='12'---  General Expenses Without Vendor
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name, (select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode!='Cash' order by Id desc
End
   
    else if @sp_status ='13'---  General Expenses Total NO VENDOR
   BEGIN
       select *,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Amount as float )) from General_expense where Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Expenses' parameter_New from General_expense where Idate>=@fromdate and  Idate<=@todate)t
End
    else if @sp_status ='14'---  Total Cash Collection
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode='Cash' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cash' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End
else if @sp_status ='15'---  Total Online Collection
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End
End");

                        list.Add(@"Alter       PROCEDURE sp_Fetch_month_dues 
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id as int,
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50)='no',
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@transportportation_id  as varchar(50),
@sp_status       VARCHAR(500)
AS
Begin
    ---------Datewise Order Count----------
    
    if @hosteltaken='yes'
    
            begin
                 if @sp_status ='1'
BEGIN
    declare @applyfor as varchar(50),@parameter as varchar(50);
    set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
    
                 select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all
select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.Session_id=tr.session_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@admission_no and tr.Month=@months

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id) t 
 END 
                 
            end 
         else
            begin
                
    if @sp_status ='1'
BEGIN
    select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter='MonthlyFee' and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all
select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.Session_id=tr.session_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@admission_no and tr.Month=@months

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id) t 
 END
 end 
End");
                        break;
                    }
                #endregion 

                #region Case 1.0.0.51 //update
                case "1.0.0.51":
                    {
                        list.Add(@"Alter              PROCEDURE sp_Fee_collection_day_end_report
@fromdate int = null,
@todate int = null,
@Type   VARCHAR(500) = NULL,
@Session   VARCHAR(500) = NULL,
@Session_id   VARCHAR(500) = NULL,
@Paymentmode   VARCHAR(500) = NULL,
@userid   VARCHAR(500) = NULL,
@Financial_year   VARCHAR(500) = NULL,
@sp_status        VARCHAR(5000)


AS
Begin




    if @sp_status = '1'-- - day boarding school hostler
      BEGIN


         if @Paymentmode = 'Cash'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by Idate asc
   END
       ELSE  if @Paymentmode = 'Cheque'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by Idate asc
   END
    ELSE
    BEGIN
        select ar.Session_id, ar.dateofadmission, ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' and ad.mode!='Cheque' order by Idate asc


     END


    END 
  else if @sp_status ='2'--- form seal
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=Form_sale_details.user_id) as User_name from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' order by idate asc
    END
         ELSE if @Paymentmode ='Cheque'
         BEGIN
             select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=Form_sale_details.user_id) as User_name from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cheque' order by idate asc
    END
    ELSE
    BEGIN
        select  Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,class,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=Form_sale_details.user_id) as User_name from Form_sale_details where  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' and Payment_Mode!='Cheque' order by idate asc


     END

    End

else if @sp_status ='3'--- other fee
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' order by ad.Payment_Idate asc
    END
         ELSE if @Paymentmode ='Cheque'
         BEGIN
             select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cheque' order by ad.Payment_Idate asc
    END
    ELSE
    BEGIN
        select ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' and ad.Payment_mode!='Cheque' order by ad.Payment_Idate asc


     END

    End


   else if @sp_status ='4'---  over all summery
   BEGIN 
       select* from(Select sum(cast(Amount as float )) as Amount,parameter_New from Student_Payment_History where  parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Session = @Session and Idate>=@fromdate and  Idate<=@todate group by parameter_New union all Select sum(cast(Amount as float )) as Amount,'Form Sale'parameter_New from Form_sale_details where     session =@Session and   Idate>=@fromdate and  Idate<=@todate union all Select sum(cast(Content_Fee as float )) as Amount,'Other Fee'parameter_New from Other_Fee_Taken_For_Student where    Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate) t where Amount>0
   
        
    End
   
   
    else if @sp_status ='5'---  user wise collection report
   BEGIN

       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id = @Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate and  ad.user_id= @userid   UNION all   select Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode where  session =@Session and  Idate>=@fromdate and  Idate<=@todate and user_id=@userid UNION all
    select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Created_by=@userid order by mode, Idate


End
   else if @sp_status ='6'---  All user wise collection report
   BEGIN


       select ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id = @Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate UNION all select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode where  session =@Session and  Idate>=@fromdate and  Idate<=@todate UNION all
select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate order by mode, Idate


End
   else if @sp_status ='7'---  General Expenses
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode='Cash' order by Id desc
End
      else if @sp_status ='8'---  General Expenses
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque' order by Id desc
End
   else if @sp_status ='80'---  General Expenses CHEQUE
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode='Cheque'  order by Id desc
End
   else if @sp_status ='9'---  Overall Amount Collection
   BEGIN
       select * from(select *, (cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cash' and Session=j.Session),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and Session=j.Session),0) as AmountOnline,parameter_New,Session from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate group by j.parameter_New,j.Session

UNION all
Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' and Session=j.Session),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' and Session=j.Session),0) as AmountOnline,'Form Sale' as parameter_New, Session  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate group by Session

UNION all
Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' and Session_id=j.Session_id),0) as AmountCash,isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' and Session_id=j.Session_id),0) as AmountOnline,'Other Fee' as parameter_New, k.Session  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate group by k.Session,j.Session_id) t)j where ttl_amount>0
End

 else if @sp_status ='10'---  General Expenses Total
   BEGIN
       select *,(cast(AmountCash as float )+cast(AmountOnline as float )+cast(AmountCheque as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque'),0) as AmountOnline,isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode='Cheque'),0) as AmountCheque,'Expenses' parameter_New from Vendor_general_expense where Payment_Idate>=@fromdate and  Payment_Idate<=@todate)t  UNION all  select *,(cast(AmountCash as float )+cast(AmountOnline as float )+cast(AmountCheque as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Amount as float )) from General_expense where Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque'),0) as AmountOnline,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cheque'),0) as AmountCheque,'Expenses' parameter_New from General_expense where Idate>=@fromdate and  Idate<=@todate)t
End
   
    else if @sp_status ='11'---  General Expenses Without Vendor
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name,(select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode='Cash' order by Id desc
End
   else if @sp_status ='12'---  General Expenses Without Vendor
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name, (select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque' order by Id desc
End
   else if @sp_status ='112'---  General Expenses Without Vendor CHEQUE
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name, (select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode='Cheque' order by Id desc
End
   
    else if @sp_status ='13'---  General Expenses Total NO VENDOR
   BEGIN
       select *,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Amount as float )) from General_expense where Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Expenses' parameter_New from General_expense where Idate>=@fromdate and  Idate<=@todate)t
End
    else if @sp_status ='14'---  Total Cash Collection
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode='Cash' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cash' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End
else if @sp_status ='15'---  Total Online Collection
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and mode!='Cheque' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and mode!='Cheque' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' and Payment_Mode!='Cheque' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash'  and Payment_Mode!='Cheque' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash'  and Payment_mode!='Cheque' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End

else if @sp_status ='16'---  Total CHEQUE Collection 
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode='Cheque' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cheque' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cheque' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cheque' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cheque' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cheque' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End
End");
                        list.Add(@"Alter             PROCEDURE sp_Fee_collection_report_new
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdate int=null,
@todate int=null,
@Session   VARCHAR(500)=NULL,
@Session_id  int=null,
@class_id  int=null,
@section   VARCHAR(500)=NULL,
@Type   VARCHAR(500)=NULL,
@parameter   VARCHAR(500)=NULL,
@Admission_no  VARCHAR(500)=NULL,
@Payment_mode  VARCHAR(500)=NULL,
@sp_status       VARCHAR(500)
AS
Begin
    
    

    ---------Collection Datewise PaymentMode---------
 if @sp_status ='1'
BEGIN
    select sum(isnull(convert(float, Amount),0)) as Paid_amt,mode from Student_Payment_History where Type=@Type and Idate>=@fromdate and Idate<=@todate  group by mode
 END

 ---------Headwise fees collection---------
 if @sp_status ='2'
BEGIN
    select DISTINCT Date,Idate from Student_Payment_History where Type=@Type and Idate>=@fromdate and Idate<=@todate   order by Idate asc
 END

  ---------Headwise fees collection---------
  if @sp_status ='3'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate=@fromdate and parameter=@parameter   group by feetype,Idate order by feetype asc
 END

  ---------Headwise fees collection---------
  if @sp_status ='4'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,Content as feetype from Monthly_Fee_Collection_Slip where Idate>=@fromdate and Idate<=@todate and parameter=@parameter  group by Content order by Content asc
 END
 ---------Headwise fees collection Class & Date---------
 if @sp_status ='5'
BEGIN
    select DISTINCT Date,Idate from Student_Payment_History where Type=@Type and Idate>=@fromdate and Idate<=@todate   and class_id=@class_id order by Idate asc
 END
 ---------Headwise fees collection Class & Date & Section---------
 if @sp_status ='6'
BEGIN
    select DISTINCT t1.Date,t1.Idate from Student_Payment_History t1 join admission_registor t2 on t1.Session=t2.Session and t1.Addmission_no=t2.admissionserialnumber and t1.Class_id=t2.Class_id where Type=@Type and t1.Idate>=@fromdate and t1.Idate<=@todate   and t1.class_id=@class_id and t2.Section=@section order by Idate asc
 END
  ---------Headwise fees collection---------
  if @sp_status ='7'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate>=@fromdate and Idate<=@todate and parameter=@parameter   and class_id=@class_id group by feetype order by feetype asc
 END
  ---------Headwise fees collection---------
  if @sp_status ='8'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate>=@fromdate and Idate<=@todate and parameter=@parameter   and class_id=@class_id and section=@section group by feetype order by feetype asc
 END

  ---------Headwise fees collection---------
  if @sp_status ='9'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate=@fromdate and parameter=@parameter   and class_id=@class_id group by feetype,Idate order by feetype asc
 END
  ---------Headwise fees collection---------
  if @sp_status ='10'
BEGIN
    select sum(isnull(convert(float, paid),0)) as Paid_amt,feetype from Typewise_fee_collection where Idate=@fromdate and parameter=@parameter   and class_id=@class_id  and section=@section group by feetype,Idate order by feetype asc
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='11'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where    ar.Transfer_Status='New' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='12'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where   ar.Transfer_Status='New' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate and ar.Class_id=@class_id) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='13'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where   ar.Transfer_Status='New' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate and ar.Class_id=@class_id and ar.Section=@section) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='14'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Admission_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where ar.Session_id =@Session_id and  ar.Transfer_Status='New' and ar.Status='1'  and ar.Class_id=@class_id and ar.admissionserialnumber=@Admission_no) t where Payable_amount>'0'
 END

  




---------Admission Fee Student Wise collection---------
  if @sp_status ='24'
BEGIN
    select * from (select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Slip_no,isnull((ad.Payable_amount),'0') as Payable_amount,isnull((ad.Paid_amount),'0') as Paid_amount,isnull((ad.Dues_amount),'0') as Dues_amount from admission_registor ar left join Annual_fee_collection ad on ar.admissionserialnumber=ad.Admission_no and ar.session=ad.session where   ar.Transfer_Status='NT' and ar.Status='1' and ad.Idate>=@fromdate and ad.Idate<=@todate) t where Payable_amount>'0'
 END
  ---------Admission Fee Student Wise collection---------
  if @sp_status ='25'
BEGIN
