                        list.Add(@"Alter                 PROCEDURE sp_Fee_collection_day_end_report
@fromdate int = null,
@todate int = null,
@Type   VARCHAR(500) = NULL,
@Session   VARCHAR(500) = NULL,
@Session_id   VARCHAR(500) = NULL,
@Paymentmode   VARCHAR(500) = NULL,
@userid   VARCHAR(500) = NULL,
@Financial_year   VARCHAR(500) = NULL,
@sp_status        VARCHAR(5000)


AS
Begin
    if @sp_status = '1'-- - day boarding school hostler
      BEGIN

         if @Paymentmode = 'Cash'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session  join Add_course_table cls on ar.Class_id=cls.course_id where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by cls.Position asc
   END
       ELSE  if @Paymentmode = 'Cheque'
         BEGIN
             select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session  join Add_course_table cls on ar.Class_id=cls.course_id where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by cls.Position asc
   END
    ELSE
    BEGIN
        select ar.Session_id, ar.dateofadmission, ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session  join Add_course_table cls on ar.Class_id=cls.course_id  where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' and ad.mode!='Cheque' order by cls.Position asc 
    END 
    END 

  else if @sp_status ='2'--- form seal
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' order by t2.Position asc
    END
         ELSE if @Paymentmode ='Cheque'
         BEGIN
             select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cheque' order by t2.Position asc
    END
    ELSE
    BEGIN
        select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' and Payment_Mode!='Cheque' order by t2.Position asc 
    END 
    End

else if @sp_status ='3'--- other fee
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  join Add_course_table cls on ar.Class_id=cls.course_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' order by cls.Position asc
    END
         ELSE if @Paymentmode ='Cheque'
         BEGIN
             select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  join Add_course_table cls on ar.Class_id=cls.course_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cheque' order by cls.Position asc
    END
    ELSE
    BEGIN
        select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  join Add_course_table cls on ar.Class_id=cls.course_id where  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' and ad.Payment_mode!='Cheque' order by cls.Position asc


     END

    End


   else if @sp_status ='4'---  over all summery
   BEGIN 
       select* from(Select sum(cast(Amount as float )) as Amount,parameter_New from Student_Payment_History where  parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Session = @Session and Idate>=@fromdate and  Idate<=@todate group by parameter_New union all Select sum(cast(Amount as float )) as Amount,'Form Sale'parameter_New from Form_sale_details where     session =@Session and   Idate>=@fromdate and  Idate<=@todate union all Select sum(cast(Content_Fee as float )) as Amount,'Other Fee'parameter_New from Other_Fee_Taken_For_Student where    Session_id =@Session_id and   Payment_Idate>=@fromdate and  Payment_Idate<=@todate) t where Amount>0
   
        
    End
   
   
    else if @sp_status ='5'---  user wise collection report
   BEGIN

       select  ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id = @Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate and  ad.user_id= @userid   UNION all   select Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode where  session =@Session and  Idate>=@fromdate and  Idate<=@todate and user_id=@userid UNION all
    select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Created_by=@userid order by mode, Idate


End
   else if @sp_status ='6'---  All user wise collection report
   BEGIN


       select ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Amount,ad.mode,ad.Date,ad.Idate,ad.Slip_no,ad.parameter_New,ad.user_id from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session join Payment_Mode_Master pmm on pmm.Type_Mode=ad.mode where ar.Session_id = @Session_id   and ad.Idate>=@fromdate and ad.Idate<=@todate UNION all select  Form_no as admissionserialnumber, session, class,'A' as Section,'0' as rollnumber, student_name as studentname,fathers_name as fathername,mobile as mobilenumber,Amount,Payment_Mode as mode,date as Date,Idate,recpt_no as Slip_no,'Form Sale' as parameter_New ,user_id from Form_sale_details join Payment_Mode_Master on Payment_Mode_Master.Type_Mode=Form_sale_details.Payment_Mode where  session =@Session and  Idate>=@fromdate and  Idate<=@todate UNION all
select ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ad.Content_Fee as Amount ,ad.Payment_mode as mode,ad.Payment_date as Date,ad.Payment_Idate as Idate,ad.Slipid as Slip_no,'Other Fee' as parameter_New,ad.Created_by as user_id from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id where ar.Session_id =@Session_id and  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate order by mode, Idate


End
   else if @sp_status ='7'---  General Expenses
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode='Cash' order by Id desc
End
      else if @sp_status ='8'---  General Expenses
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque' order by Id desc
End
   else if @sp_status ='80'---  General Expenses CHEQUE
   BEGIN
       select*,(select top 1 Company_name +', (Mobile No. : '+Mobile_no+')' from Vendor_master where Vendor_id = Vendor_general_expense.Vendor_id) as Vendor_Name,(select top 1 Session from session_details where session_id=Vendor_general_expense.Financial_year) as Session_name,(select top 1 name from user_details where user_id=Vendor_general_expense.Created_by) as User_name from Vendor_general_expense where Payment_idate>=@fromdate and Payment_idate<=@todate and Payment_mode='Cheque'  order by Id desc
End
   else if @sp_status ='9'---  Overall Amount Collection
   BEGIN
       select * from(select *, (cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cash' and Session=j.Session),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Student_Payment_History where parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and Session=j.Session),0) as AmountOnline,parameter_New,Session from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate group by j.parameter_New,j.Session

UNION all
Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' and Session=j.Session),0) as AmountCash,isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' and Session=j.Session),0) as AmountOnline,'Form Sale' as parameter_New, Session  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate group by Session

UNION all
Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' and Session_id=j.Session_id),0) as AmountCash,isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' and Session_id=j.Session_id),0) as AmountOnline,'Other Fee' as parameter_New, k.Session  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate group by k.Session,j.Session_id) t)j where ttl_amount>0
End

 else if @sp_status ='10'---  General Expenses Total
   BEGIN
       select *,(cast(AmountCash as float )+cast(AmountOnline as float )+cast(AmountCheque as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque'),0) as AmountOnline,isnull((select sum(cast(Payment_amount as float )) from Vendor_general_expense where Payment_idate>=@fromdate and  Payment_idate<=@todate and Payment_mode='Cheque'),0) as AmountCheque,'Expenses' parameter_New from Vendor_general_expense where Payment_Idate>=@fromdate and  Payment_Idate<=@todate)t  UNION all  select *,(cast(AmountCash as float )+cast(AmountOnline as float )+cast(AmountCheque as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Amount as float )) from General_expense where Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque'),0) as AmountOnline,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cheque'),0) as AmountCheque,'Expenses' parameter_New from General_expense where Idate>=@fromdate and  Idate<=@todate)t
End
   
    else if @sp_status ='11'---  General Expenses Without Vendor
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name,(select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode='Cash' order by Id desc
End
   else if @sp_status ='12'---  General Expenses Without Vendor
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name, (select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque' order by Id desc
End
   else if @sp_status ='112'---  General Expenses Without Vendor CHEQUE
   BEGIN
       select * ,(select top 1 Session from session_details where session_id=General_expense.Session_id) as Session_name, (select top 1 name from user_details where user_id=General_expense.Created_by) as User_name from General_expense where Idate>=@fromdate and Idate<=@todate and Payment_mode='Cheque' order by Id desc
End
   
    else if @sp_status ='13'---  General Expenses Total NO VENDOR
   BEGIN
       select *,(cast(AmountCash as float )+cast(AmountOnline as float ))  as ttl_amount from(Select top 1 isnull((select sum(cast(Amount as float )) from General_expense where Idate>=@fromdate and  Idate<=@todate and Payment_mode='Cash'),0) as AmountCash,isnull((select sum(cast(Amount as float )) from General_expense where  Idate>=@fromdate and  Idate<=@todate and Payment_mode!='Cash'),0) as AmountOnline,'Expenses' parameter_New from General_expense where Idate>=@fromdate and  Idate<=@todate)t
End
    else if @sp_status ='14'---  Total Cash Collection
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode='Cash' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cash' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cash' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cash' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End
else if @sp_status ='15'---  Total Online Collection
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and mode!='Cheque' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and mode!='Cheque' and Transection_in!='App' group by j.parameter_New,j.Session,user_id

UNION all

select isnull(sum(cast(AmountCash as float )),0) as AmountCash,parameter_New,Session,'App' as user_id,'Students' as User_name, Sequence from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and mode!='Cheque' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode!='Cash' and mode!='Cheque' and Transection_in='App' group by j.parameter_New,j.Session,user_id) x group by parameter_New,Session,Sequence
 
UNION all

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash' and Payment_Mode!='Cheque' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode!='Cash'  and Payment_Mode!='Cheque' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash' and Payment_mode!='Cheque' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode!='Cash'  and Payment_mode!='Cheque' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End

else if @sp_status ='16'---  Total CHEQUE Collection 
   BEGIN
       select * from (select isnull((select sum(cast(Amount as float )) from Student_Payment_History where user_id=j.user_id and  parameter_New = j.parameter_New and parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee') and Idate>=@fromdate and  Idate<=@todate and mode='Cheque' and Session=j.Session),0) as AmountCash,parameter_New,Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,(select top 1 Sequence from Fee_sequience where Fee_type=j.parameter_New) as Sequence from Student_Payment_History j where parameter_New in('AdmissionFee','AnnualFee','HostelAdmissionFee','HostelAnnualFee','HostelMonthlyFee','MonthlyFee')  and Idate>=@fromdate and  Idate<=@todate and mode='Cheque' group by j.parameter_New,j.Session,user_id

UNION all
 

Select isnull((select sum(cast(Amount as float )) from Form_sale_details where Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cheque' and Session=j.Session and user_id=j.user_id),0) as AmountCash,'Form Sale' as parameter_New, Session,user_id,(select top 1 name from user_details where user_id=j.user_id) as User_name,'9' as Sequence  from Form_sale_details j  where  Idate>=@fromdate and  Idate<=@todate and Payment_Mode='Cheque' group by Session,user_id


UNION all

Select isnull((select sum(cast(Content_Fee as float )) from Other_Fee_Taken_For_Student where Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cheque' and Session_id=j.Session_id and Created_by=j.Created_by),0) as AmountCash,'Other Fee' as parameter_New, k.Session,j.Created_by as user_id,(select top 1 name from user_details where user_id=j.Created_by) as User_name,'8' as Sequence  from Other_Fee_Taken_For_Student j join session_details k on j.session_id=k.session_id where  Payment_Idate>=@fromdate and  Payment_Idate<=@todate and Payment_mode='Cheque' group by k.Session,j.Session_id ,j.Created_by) t order by Sequence asc
End
End");
                        list.Add("update MenuPermissionForUser_web set Is_Edit='1',Is_delete='1',Is_Download='1',Is_Print='1',Is_add='1'");

                        list.Add(@"Alter          PROCEDURE sp_update_admission_no_and_Class
 @admissionserialnumber_old       varchar(500) =NULL,
@admissionserialnumber       varchar(500) =NULL,
@Session_id         varchar(500) =NULL,
@updated_by         varchar(500) =NULL,
@updated_date       varchar(500) =NULL,
@session varchar(500) =NULL,
@Class_id varchar(500) =NULL,
@slip_no varchar(500) =NULL,
@rollno_old varchar(500) =NULL,
@Roll_no_New varchar(500) =NULL,
@Class_idnew varchar(500) =NULL,
@Class_name varchar(500) =NULL,
@Old_section varchar(500) =NULL,
@New_Section varchar(500) =NULL,

@Branch_id varchar(500) =NULL,
@status        VARCHAR(5000)
 
AS
Begin 

            ----Insert new data----

            if @status ='updateadmissionno'
             Begin  
        
                 update admission_registor set admissionserialnumber=@admissionserialnumber where admissionserialnumber=@admissionserialnumber_old and Session_id=@Session_id
                 
                 INSERT INTO admission_registor_Change_admission_no_history (Old_admission_no,Current_admission_no,Session_id,Created_By,Date_time,Change_type,Branch_id) values (@admissionserialnumber_old,@admissionserialnumber,@Session_id,@updated_by,@updated_date,'Admission No. Change',@Branch_id)
                 
                 update Student_mapping_with_boarding_with_lunch set Admission_no=@admissionserialnumber where Session_id=@Session_id and Admission_no=@admissionserialnumber_old
                 update Admission_fee_collection set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                 update Annual_fee_collection set  Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                 update Discount_Master set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session_id=@Session_id
                 
                 update Discount_Master_for_bus set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session_id=@Session_id
                 
                 update Discount_Master_Monthly_Studentwise set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update Fine_Fees_collection set Admission_no=@admissionserialnumber where  Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update lib_student_transaction_details set student_id=@admissionserialnumber where student_id=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update Monthly_Fee_Collection_Slip set adno=@admissionserialnumber where adno=@admissionserialnumber_old and session=@session
                 
                 update Payment_transaction_process set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update SchoolLedger set Addmission_no=@admissionserialnumber where  Addmission_no=@admissionserialnumber_old and session=@session
                 
                  update Student_Payment_History set Addmission_no=@admissionserialnumber where Addmission_no=@admissionserialnumber_old and Session=@session
                  
                
                 
                 update Typewise_fee_collection set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session=@session
                 
                 ------------------LMS----------
                 update Zoom_Meeting_Joining_Status set User_id=@admissionserialnumber where User_id=@admissionserialnumber_old and Session_id=@Session_id
                 update user_test_total_marks_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and Session_Id=@Session_id
                 
                 update user_test_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and  Session_id=@Session_id
                 update user_test_attempted_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and  Session_id=@Session_id
                 
                 update Subjective_particpation set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_id=@Session_id
                 
                 update Subjective_Pdf_Answer set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                 
                  update Subjective_marks_chart set Studnet_Id=@admissionserialnumber where Studnet_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                  
                  update Subjective_answer set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                  
                   update Subject_Mapping_New set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                   
                   update Student_Remarks_Entry set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id
                   
                   
                   update Student_Practical_Viva_Marks set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id
                   
                   
                   update Student_Attendance_saved_Class_Wise set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
              End
               else  if @status ='updateclass'
                Begin  
                 
                    INSERT INTO Student_Payment_History_Save_bakup (Addmission_no,Session,Date,Idate,Description,Entry_id,Slip_no,Amount,Type,mode,discount,Discoun_in_School,Discoun_in_Hostel,Discoun_in_Transport,fine,is_ofline_sync,Is_online_sync,is_update_in_online,Previous_admission_no,App_Transection_id,time,user_id,Acamedic_Semester_Id,Branch,Class_id,User_Slip_no,Pay_mode_transaction_no,Money_Receipt_Date,Money_Receipt_Idate,Unique_id,Adjust_type,Remarks,Transection_in,insert_time_date,Insert_time_user_id,New_Slip_no)
                    SELECT Addmission_no,Session,Date,Idate,Description,Entry_id,Slip_no,Amount,Type,mode,discount,Discoun_in_School,Discoun_in_Hostel,Discoun_in_Transport,fine,is_ofline_sync,Is_online_sync,is_update_in_online,Previous_admission_no,App_Transection_id,time,user_id,Acamedic_Semester_Id,Branch,Class_id,User_Slip_no,Pay_mode_transaction_no,Money_Receipt_Date,Money_Receipt_Idate,Unique_id,Adjust_type,Remarks,Transection_in,@updated_date,@updated_by,@slip_no
                 FROM Student_Payment_History where Addmission_no=@admissionserialnumber and Session=@session and Class_id=@Class_id
                 
                 
                 update admission_registor set admissionserialnumber=@admissionserialnumber,rollnumber=@Roll_no_New,Section=@New_Section,class=@Class_name,Class_id=@Class_idnew,payment_status='Unpaid'    where admissionserialnumber=@admissionserialnumber_old and Session_id=@Session_id 
                  
                  
                  
                 INSERT INTO admission_registor_Change_admission_no_history (Old_admission_no,Current_admission_no,Session_id,Created_By,Date_time,Change_type,Old_Class_id,Class_Id_New,Roll_no_old,Roll_no_New,Slip_no,Old_Section_name,New_Section,Branch_id) values (@admissionserialnumber_old,@admissionserialnumber,@Session_id,@updated_by,@updated_date,'Class Name Change',@Class_id,@Class_idnew,@rollno_old,@Roll_no_New,@slip_no,@Old_section,@New_Section,@Branch_id)
                   
                   
                 ---------------delete from payment history---------------
                 
                 delete from Admission_fee_collection where Admission_no=@admissionserialnumber and session=@session
                 delete from Annual_fee_collection  where Admission_no=@admissionserialnumber and session=@session
                 delete Student_mapping_with_boarding_with_lunch   where Session_id=@Session_id and Admission_no=@admissionserialnumber
                 
                   delete Discount_Master  where admission_no=@admissionserialnumber and session_id=@Session_id
                 
                   delete Discount_Master_for_bus   where admission_no=@admissionserialnumber and session_id=@Session_id
                 
                   delete Discount_Master_Monthly_Studentwise   where Admission_no=@admissionserialnumber and Session_id=@Session_id
                   delete Fine_Fees_collection   where  Admission_no=@admissionserialnumber and Session_id=@Session_id
                   
                    delete Monthly_Fee_Collection_Slip   where adno=@admissionserialnumber and session=@session
                 
                    delete Payment_transaction_process   where Admission_no=@admissionserialnumber and Session_id=@Session_id
                 
                    delete SchoolLedger  where  Addmission_no=@admissionserialnumber and session=@session
                 
                    delete Student_Payment_History  where Addmission_no=@admissionserialnumber and Session=@session
                  
                
                 
                    delete Typewise_fee_collection   where admission_no=@admissionserialnumber and session=@session
                   
                   
                   
                   
                   
                End
    

End");
                        list.Add(@"create proc sp_fetch_monthly_fee_discount
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id as int,
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50)='no',
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@monthid  as int=0,
@transportportation_id  as varchar(50)
as 
begin 
    declare @applyfor as varchar(50),@parameter as varchar(50);
  
        if @hosteltaken='yes'
            begin
                 set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
                 select 'Monthly' as Type,@months as Month, isnull(sum(convert(float, disc_amount)),'0') as Total_disc from (select (isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months   union all  
             select (isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount
                 from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@Admission_No and tr.Month=@months and tr.Session=@session join Student_mapping_with_TransportPath smt on  ar.Session_id=smt.Session_id and ar.admissionserialnumber=smt.Admission_no and smt.Year_month<=@monthid)t;
                 
            end 
         else
            begin
                set @applyfor='Day Scholar';
                 set @parameter='MonthlyFee'; 
                 --set @parameter_id='4'; 
                 select 'Monthly' as Type,@months as Month, isnull(sum(convert(float, disc_amount)),'0') as Total_disc from (select (isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from Fee_master_content_wise fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter and fmc.Month=@months and fmc.parameter_id=@parameter_id

UNION all
select (isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and Bus_path=@transportportation_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and Bus_path=@transportportation_id))) disc_amount
                 from admission_registor ar join Transportation_Fee_Master tr on ar.Transportation_Id=tr.Transportation_path_id and ar.transportationtaken='yes' and ar.Session_id=@session_id and admissionserialnumber=@Admission_No and tr.Month=@months and tr.Session=@session join Student_mapping_with_TransportPath smt on  ar.Session_id=smt.Session_id and ar.admissionserialnumber=smt.Admission_no and smt.Year_month<=@monthid) t
          end
end");
                        break;
                    }
                #endregion

                #region Case 1.0.0.55 //update
                case "1.0.0.55":
                    {
                        list.Add(@"Alter Table dbo.[Form_sale_details] Add [Admission_no] varchar (500)  ;");
                        list.Add(@"Alter Table dbo.[Form_sale_details] Add [Admission_no_updated_on] varchar (500)  ;");
                        list.Add(@"Alter Table dbo.[Form_sale_details] Add [Is_admission_no_updated] int  ;");
                        list.Add(@"Alter                 PROCEDURE sp_Graph_Report
@Sdate           VARCHAR(500)=NULL,
@Sidate           int=NULL,
@fromdate int=null,
@todate int=null,
@Storeid      VARCHAR(500)=NULL,
@Session   VARCHAR(500)=NULL,
@Session_id  int=null,
@Class_id  VARCHAR(500)=NULL,
@Class_name  VARCHAR(500)=NULL,
@Parameter  VARCHAR(500)=NULL,
@MonthPosition  int=null,
@prevs_month_position  int=null,
@fromIdate  int=null,
@toIdate  int=null,
@MonthName  VARCHAR(500)=NULL,
@PrevMonthName  VARCHAR(500)=NULL,
@sp_status       VARCHAR(500)
AS
Begin
    

    ---------Datewise Order Count----------
    if @sp_status ='1'
BEGIN
    -- select count(id) as total_adm,class from dbo.[admission_registor] t1 where    (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Status='1'   group by t1.class
    
       select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV'   and t1.Status='1' group by t1.class,cm.Position order by cm.Position
 END

 ---------Payment History---------
 if @sp_status ='2'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id 
 END
  ---------Dues Payment----------
  if @sp_status ='3'
BEGIN
     select class,isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection] where class_id=admission_registor.Class_id),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise] where class_id=admission_registor.Class_id))),'0') total_amt from dbo.[admission_registor] group by Class_id,class
 END
   ---------Dues/Pais Payment----------
   if @sp_status ='4'
BEGIN
     select * from (select 'Dues' as Status, isnull((isnull((select sum(cast(dues as float)) from dbo.[Typewise_fee_collection]),(select sum(cast(amount as float)) from dbo.[Fee_master_content_wise]))),'0') total_amt from dbo.[admission_registor]) t group by t.total_amt,t.Status UNION all select * from (select 'Paid' as Status,isnull((select sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 ) t group by t.total_amt,t.Status
 END
 
 
   ---------Dashboard2---------
  ---------Dashboard2 Payment History---------
  if @sp_status ='5'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END

 ---------Dues Payment----------
 if @sp_status ='6'
BEGIN
     select class,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class
 END
  ---------Dues/Paid Payment----------
  if @sp_status ='7'
BEGIN
     select 'Dues' as Status,sum(Final_Amount)-sum(total_amt) total_amt  from(select class,cast(t1.Final_Amount as float) Final_Amount,sum(isnull(convert(float, t1.Paid_Amount),0)) as total_amt from admission_registor t2 join Student_Payment_History_Bill_wise_New_Payment t1 on t1.Addmission_no=t2.admissionserialnumber and t1.Session_id=t2.Session_id and t1.Acamedic_Semester_Id=t2.Academic_Sem_or_Year_id  group by class,t1.Class_id,t1.Final_Amount)t group by class  UNION all select 'Paid' as Status,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id),0) as total_amt from admission_registor group by class,Class_id
 END
  ---------Payment paid his----------
  if @sp_status ='8'
BEGIN
     select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id group by t2.class,t1.Class_id
 END
  ---------Payment History Session Wise---------
  if @sp_status ='9'
BEGIN
    select t2.class,isnull((select  sum(isnull(convert(float, paid),0)) from Typewise_fee_collection where Class_id=t1.Class_id),0) as total_amt from Student_Payment_History t1 join admission_registor t2 on t1.Class_id=t2.Class_id and t1.Session=t2.session where t2.Session_id=@Session_id  group by t2.class,t1.Class_id
 END
  if @sp_status ='10'
BEGIN
    select class,isnull((select sum(isnull(convert(float, Paid_Amount),0)) from Student_Payment_History_Bill_wise_New_Payment where Class_id=admission_registor.Class_id and Session_id=admission_registor.Session_id),0) as total_amt from admission_registor where Session_id=@Session_id group by class,Class_id,Session_id
 END

  if @sp_status ='11'
BEGIN
    select count(t1.id) as total_adm,t1.class from dbo.[admission_registor] t1 join Add_course_table cm  on cm.course_id=t1.Class_id where  (t1.Transfer_Status='New' or t1.Transfer_Status='NT') and t1.StudentStatus='AV' and t1.Session_id=@Session_id and t1.Status='1' group by t1.class,cm.Position order by cm.Position
 END
  if @sp_status ='12'
BEGIN
