                        list.Add(@"Alter  PROCEDURE sp_Fee_collection_day_end_report
@fromdate int = null,
@todate int = null,
@Type   VARCHAR(500) = NULL,
@Session   VARCHAR(500) = NULL,
@Session_id   VARCHAR(500) = NULL,
@Paymentmode   VARCHAR(500) = NULL,
@userid   VARCHAR(500) = NULL,
@Financial_year   VARCHAR(500) = NULL,
@Class_id   VARCHAR(500) = NULL,
@Class_name   VARCHAR(500) = NULL,
@sp_status        VARCHAR(5000)


AS
Begin
    if @sp_status = '1'-- - day boarding school hostler
    BEGIN 
         if @Paymentmode = 'Cash'
         BEGIN
             if @Class_id = '0'
              BEGIN
                  select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by cls.Position asc
             END
             ELSE
             BEGIN
                 select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode and ar.Class_id=@Class_id order by cls.Position asc
             END 
          END
       ELSE  if @Paymentmode = 'Cheque'
         BEGIN
             if @Class_id = '0'
              BEGIN
                  select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode order by cls.Position asc
                END
             ELSE
             BEGIN
                 select ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode=@Paymentmode and ar.Class_id=@Class_id order by cls.Position asc
             END
         END
         ELSE
         BEGIN
             if @Class_id = '0'
              BEGIN
                 select ar.Session_id, ar.dateofadmission, ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id  where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' and ad.mode!='Cheque' order by cls.Position asc 
              END
             ELSE
             BEGIN
                 select ar.Session_id, ar.dateofadmission, ar.admissionserialnumber, ar.session, ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,Amount,ad.mode,ad.Date,ad.Slip_no,(select top 1 name from user_details where user_id=ad.user_id) as User_name,ad.Remarks,ad.Pay_mode_transaction_no from admission_registor ar  join Student_Payment_History ad on ar.admissionserialnumber=ad.Addmission_no and ar.session=ad.Session  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id  where ad.parameter_New=@Type and ad.Idate>=@fromdate and ad.Idate<=@todate and ad.mode!='Cash' and ad.mode!='Cheque' and ar.Class_id=@Class_id order by cls.Position asc 
              END
         END 
    END 

  ------------------------------
  else if @sp_status ='2'--- form seal
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
              if @Class_id = '0'
              BEGIN
                  select t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' order by t2.Position asc
             END
             ELSE
             BEGIN
                 select t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cash' and t2.course_id=@Class_id order by t2.Position asc
              END
                 
         END
         ELSE if @Paymentmode ='Cheque'
         BEGIN
             if @Class_id = '0'
              BEGIN
                  select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cheque' order by t2.Position asc
              END
              ELSE
              BEGIN
                   select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where Idate>=@fromdate and  Idate<=@todate and  Payment_Mode='Cheque' and t2.course_id=@Class_id order by t2.Position asc
              END
          END
          ELSE
          BEGIN
              if @Class_id = '0'
              BEGIN
                  select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' and Payment_Mode!='Cheque' order by t2.Position asc 
              END
              ELSE
              BEGIN
                  select  t1.Id,Form_no, session, class,'A' as section,'0' as roll_no, student_name,fathers_name,mobile,Amount,Payment_Mode,date,recpt_no,(select top 1 name from user_details where user_id=t1.user_id) as User_name,Remarks,Transaction_no from Form_sale_details t1 join Add_course_table t2 on t1.class=t2.Course_Name where  Idate>=@fromdate and  Idate<=@todate and  Payment_Mode!='Cash' and t2.course_id=@Class_id  and Payment_Mode!='Cheque' order by t2.Position asc 
              END
          END 
    End
  --------------------------------------------------------------------
    else if @sp_status ='3'--- other fee
    BEGIN
          if @Paymentmode ='Cash'
         BEGIN
             if @Class_id = '0'
              BEGIN
                  select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' order by cls.Position asc
              END
              ELSE
              BEGIN
                  select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cash' and ad.Class_id=@Class_id order by cls.Position asc
             END
          END
         ELSE if @Paymentmode ='Cheque'
         BEGIN
             if @Class_id = '0'
              BEGIN
                   select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cheque' order by cls.Position asc
               END
               ELSE
               BEGIN
                   select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode='Cheque'  and ad.Class_id=@Class_id order by cls.Position asc
                    END
              END
              ELSE
              BEGIN
                  if @Class_id = '0'
                  BEGIN
                  select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' and ad.Payment_mode!='Cheque' order by cls.Position asc
              END
              ELSE
              BEGIN
                  select ad.Id,ar.studentname,ar.Session_id,ar.dateofadmission,ar.admissionserialnumber,ar.session,ar.class,ar.Section,ar.rollnumber,ar.studentname,ar.fathername,ar.mobilenumber,ar.Class_id,ad.Content_Fee,ad.Payment_mode,ad.Payment_date,ad.Slipid,(select top 1 name from user_details where user_id=ad.Created_by) as User_name,ad.Remarks,ad.Transaction_no from admission_registor ar  join Other_Fee_Taken_For_Student ad on ar.admissionserialnumber=ad.Admission_no and ar.Session_id=ad.Session_id  and ar.Class_id=ad.Class_id join Add_course_table cls on ar.Class_id=cls.course_id where  ad.Payment_Idate>=@fromdate and ad.Payment_Idate<=@todate and ad.Payment_mode!='Cash' and ad.Payment_mode!='Cheque' and ad.Class_id=@Class_id order by cls.Position asc 
              END
          END 
    End

      ---------------------------------------------------------------
   else if @sp_status ='4'---  over all summery
   BEGIN 
       if @Class_id = '0'
              BEGIN
