                        list.Add(@"CREATE   PROCEDURE sp_library_dashboard
@sessionid        varchar(5000) =NULL,
@idate       varchar(5000) =NULL,
@status        VARCHAR(5000)
 
AS
Begin 

    if(@status='0')
    BEGIN
       
        Select count(distinct BookId ) as totalAbvilable,( select  count(book_no) from dbo.[lib_student_transaction_details] where Session_id=@sessionid and status='Issued' ) as issued_book_student,( select  count(book_no) from dbo.[lib_teacher_trans_action_details] where Session_id=@sessionid and status='Issued') as issued_book_staff,(select  count(book_no) from dbo.[lib_student_transaction_details] where status='Return' and  Session_id=@sessionid)  as returned_book_student,(select  count(book_no) from dbo.[lib_teacher_trans_action_details] where status='Return' and  Session_id=@sessionid)  as returned_book_staff, (select sum(cast(Total_Fine as float))   from dbo.[lib_student_transaction_details] where Session_id=@sessionid and status='Return' ) as Total_Fine_student,(select sum(cast(Total_Fine as float)) from dbo.[lib_teacher_trans_action_details] where Session_id=@sessionid and status='Return') as Total_fine_staff,( select count(lib_card_no) from dbo.[admission_registor] where (lib_card_no!='' and lib_card_no is not null) and Session_id=@sessionid) as totall_issued_card_for_student     from dbo.[Library_Book_Entry] where Issued_Status='Not Issued'
        
    END
    
    ELSE if(@status='1')
    BEGIN
        Select count(distinct BookId ) as totalAbvilable,( select  count(book_no) from dbo.[lib_student_transaction_details] where Session_id=@sessionid and issue_idate=@idate and status='Issued') as issued_book_student,( select  count(book_no) from dbo.[lib_teacher_trans_action_details] where Session_id=@sessionid and issue_idate=@idate and status='Issued') as issued_book_staff,(select  count(book_no) from dbo.[lib_student_transaction_details] where status='Return' and  Session_id=@sessionid and return_idate=@idate)  as returned_book_student,(select  count(book_no) from dbo.[lib_teacher_trans_action_details] where status='Return' and  Session_id=@sessionid and  return_idate=@idate)  as returned_book_staff, (select sum(cast(Total_Fine as float))   from dbo.[lib_student_transaction_details] where Session_id=@sessionid and return_idate=@idate and status='Return') as Total_Fine_student,(select sum(cast(Total_Fine as float)) from dbo.[lib_teacher_trans_action_details] where Session_id=@sessionid and return_idate=@idate and status='Return') as Total_fine_staff,( select count(lib_card_no) from dbo.[admission_registor] where (lib_card_no!='' and lib_card_no is not null) and Session_id=@sessionid and lib_card_IssueIdate=@idate) as totall_issued_card_for_student     from dbo.[Library_Book_Entry] 
    

 End
    
   
     --Over ALL
            
End");

