                        list.Add(@"create PROCEDURE [dbo].[sp_sync_attendance_list]
    @attendance_list attendance_list READONLY
AS
BEGIN
    
    MERGE INTO PRL_Attendance_Log pa
      USING @attendance_list al
      ON pa.Employee_id=al.Employee_id and pa.DateTime=al.DateTime
      WHEN MATCHED THEN
      UPDATE SET
      pa.DateTime=al.DateTime
      WHEN NOT MATCHED THEN
      INSERT (Employee_id,DateTime) VALUES(al.Employee_id,al.DateTime);
        
END");
