                        list.Add(@"CREATE           PROCEDURE [dbo].[sp_HR_Attendance_Chart_Monthly] 
@StartDate varchar(200),
@EndDate varchar(200),
@Status varchar(200)='Active'
 
 
AS
Begin
    DECLARE @Columns NVARCHAR(MAX);
    
            SELECT @Columns = STUFF(
                (
                    SELECT ', ' + QUOTENAME(short_day)
            
                    FROM HR_Calendar
            
                    WHERE Idate >= @StartDate AND Idate <= @EndDate
            
                    ORDER BY Idate
            
                    FOR XML PATH(''), TYPE
                ).value('.', 'NVARCHAR(MAX)'),
    1, 2, ''
);
            DECLARE @SqlQuery NVARCHAR(MAX);
            
           
           -- SET @SqlQuery = 'select *  from (select short_day, Concat(isnull( Format(Convert( DateTime,d.In_Time),''hh:mm''),''''),char(13),isnull( Format(Convert( DateTime,d.Out_Time),''hh:mm''),'''')) In_Time,d.Employee_id,em.Employee_Name,em.Emp_Code,em.Employee_Image from  HR_Calendar c left join HR_Daily_Attendance_Record d on d.Idate=c.Idate left join hr_employee_master em on em.Employee_Id=d.Employee_Id    where   em.ActiveStatus='''+@Status+'''   and  c.Idate>=' + @StartDate + ' and c.Idate<=' + @EndDate + ' ) t
           
           SET @SqlQuery = 'select *  from ( select short_day, Concat(isnull( Format(Convert( DateTime,d.In_Time),''hh:mm''),''''),char(13),isnull( Format(Convert( DateTime,d.Out_Time),''hh:mm''),'''')) In_Time,d.Employee_id,em.Employee_Name,em.Emp_Code,em.Employee_Image from  hr_employee_master em  left join HR_Daily_Attendance_Record d on em.Employee_id=d.Employee_id  and  d.Idate>=' + @StartDate + ' and d.Idate<=' + @EndDate + '   left  join HR_Calendar c on  d.Idate=c.Idate    where   em.ActiveStatus='''+@Status+''' ) t
            
          
            
           
            
PIVOT
(
Min(In_Time) FOR short_day IN(' + @Columns + ')
) AS PivotTable where Employee_id is not null';

EXEC(@SqlQuery);
         -- SELECT @SqlQuery AS GeneratedQuery;
            END");
                        list.Add(@"CREATE      PROCEDURE [dbo].[sp_HR_Attendance_Report]

@Idate1 varchar(200),
@Idate2 varchar(200),
@UserID varchar(50)
AS
Begin
  
     declare @date_stuff varchar(5000)     
     declare @Desg varchar(50)
       
    select @date_stuff = STUFF(
    (SELECT  ',' + '[' + cast(short_day as varchar(50)) + ']' FROM HR_Calendar where Idate>=@Idate1  and Idate<=@Idate2 order by idate asc   FOR XML PATH ('')), 1, 1, '') from HR_Calendar          
    declare @qry varchar(max) ='select  Display_contnt as Days  ,'+ @date_stuff+' from 
 (
 select Days,Value,day,Filed_id,Display_contnt from (
 SELECT  

  Days,
  Value,
  day
FROM  

(SELECT day, 
Case when day_name=''Sun'' and Duration=''00:00'' Then  convert(varchar(50),''WO'') 
else case when day_name=''Sun'' and Duration !=''00:00'' then convert(varchar(50),''WOP'') 
else Case when day_name!=''Sun'' and Duration =''00:00'' then convert(varchar(50),''A'') else convert(varchar(50),''P'') End End end  as Status,
  cast( In_Time as varchar(50)) In_Time,
  cast( d_ot as varchar(50)) Out_Time,    
  cast(Late_hour as varchar(50)) Late_hour,
  cast(Early_hour as varchar(50)) Early_hour,  
  cast(day_name as varchar(50)) day_name,  
 cast(OT as varchar(50)) OT,    
 cast(Shift as  varchar(50)) Shift,    
  Duration              
        FROM(                 
        select  CASE
        WHEN DATEDIFF(SECOND, isnull( a.Out_Time, a.In_Time), a.In_Time) <=0
        THEN  convert(varchar(5),convert(varchar(50),CONVERT(TIME,  DATEADD(SECOND, - DATEDIFF(SECOND, isnull( a.Out_Time, a.In_Time), a.In_Time),''00:00''))))       
        WHEN DATEDIFF(SECOND, isnull( a.Out_Time, a.In_Time), a.In_Time) >0
        THEN  convert(varchar(50),''00:00'')
        END AS  Duration 
    ,a.id,a.Employee_id,a.Date,Format(Convert( DateTime,a.In_Time),''hh:mm'') In_Time,isnull( Format(Convert( DateTime,a.Out_Time),''hh:mm''),'''') Out_Time,a.Out_Time d_ot,a.In_Time  Atnd_Status,a.Idate,short_day Day,day_name,
     
    CASE WHEN DATEDIFF(MINUTE, isnull(s.In_Time, a.In_Time), a.In_Time) >15
        THEN  convert(varchar(5),convert(varchar(50),CONVERT(TIME,  DATEADD(SECOND, - DATEDIFF(SECOND, isnull( a.In_Time,s.In_Time), s.In_Time),''00:00''))))      
    else  convert(varchar(50),''00:00'')  END as Late_hour, 
    
    
    CASE
        WHEN DATEDIFF(Minute, isnull(  a.Out_Time, a.In_Time),s.Out_Time) >0
        THEN  convert(varchar(5),convert(varchar(50),CONVERT(TIME,  DATEADD(SECOND, - DATEDIFF(SECOND,  s.Out_Time,isnull(  a.Out_Time, a.In_Time)),''00:00''))))       
       ELSE     convert(varchar(50),''00:00'') 
   END as Early_hour,
        
     CASE
     WHEN DATEDIFF(Minute,s.Out_Time, isnull(  a.Out_Time, a.In_Time)) >=0
     THEN  convert(varchar(5),convert(varchar(50),CONVERT(TIME,  DATEADD(SECOND, - DATEDIFF(SECOND,  isnull(  a.Out_Time, a.In_Time),s.Out_Time),''00:00'')))) 
ELSE     convert(varchar(50),''00:00'') 
END as  OT,s.ShiftName as Shift                  
from HR_Calendar c left join HR_Daily_Attendance_Record a on c.idate=a.idate join HR_ShiftSetting s on a.Shift_Id=s.ShiftId where a.Idate>= '+ @Idate1 +' and a.Idate<='+ @Idate2 +'  and a.Employee_id ='''+ @UserID +''') p3
       )p   
       UNPIVOT (Value For Days  In (Status, In_Time,Out_Time,Duration,Late_hour,Early_hour,OT,Shift,day_name)
  ) tblPivot
  
  ) p1 join HMS_attebt_fields ht on Days=ht.Filed_name)p2
pivot
(
max(Value) 
FOR Day IN ('+@date_stuff+')
)t1 order by Filed_id'

EXEC(@qry)  
END");
                        list.Add(@"CREATE     Procedure sp_HR_before_salary_calculation
@year  varchar(50) = NULL,
@month_id  varchar(50) = NULL 

AS
Begin
-- Your code here
declare @month as  varchar(50)
set  @month = @year +@month_id  +'%'
select Employee_Name,Employee_Id,Emp_Code,Designation_id,DateName( month , DateAdd( month ,cast(@month_id as int) , -1 ) ) Month,@year Year,Days_in_Month, week_off,(Full_Day_Persent+Half_Day_Persent+Paid_Leave)/6 Calculated_Week_off,Days_in_Month-week_off Working_Days,Full_Day_Persent,Half_Day_Persent,Extra_Shift,Late_Comming_Days,Paid_Leave,UnPaidLeave,Half_Pay_leave,0.0 Late_Deduction, Full_Day_Persent+Extra_Shift+Half_Day_Persent/2.0+Paid_Leave+week_off+Half_Pay_leave/2.0-UnPaidLeave Paid_Days,  Grade,income_heads,deduction_heads from 

(select  Employee_Name,Employee_Id,Emp_Code ,em.Designation_id,(select grade_name from HR_Grade_Master where grade_id=em.Grade_id)  Grade,income_heads,deduction_heads, DAY(EOMONTH(@year+'-'+@month_id+'-01'))  Days_in_Month, 
iif((select count(id) from HR_Roster_Wise_Weekoff_setting where EmployeeID=em.Employee_Id and Idate like @month)=0,(select count(id) from HR_Calendar where idate like @month  and (select weekly_off from HR_Grade_Master where grade_id=em.Grade_Id)  like '%'+day_name+'%' ),(select count(id) from HR_Roster_Wise_Weekoff_setting where EmployeeID=em.Employee_Id and Idate like @month)) week_off,  
Grade_ID    ,( select count(AttendanceStatus) from HR_Daily_Attendance_Record where AttendanceStatus='Present' and Employee_id=em.Employee_id and Idate like @month) Full_Day_Persent ,( select count(Id) from HR_Extra_Shift_Working where Employee_Id=em.Employee_id and Idate like @month) Extra_Shift ,
( select count(AttendanceStatus) from HR_Daily_Attendance_Record where AttendanceStatus='Half Day' and Employee_id=em.Employee_id and Idate like @month)  Half_Day_Persent,
0   Late_Half_Day_Deduction, 0  Full_Day_Deduction, 
( select count(id) from HR_Daily_Attendance_Record where Late_Minute>isnull((select Top 1 Allowed_Late_Come from HR_Salary_And_Attendance_Rule),10) and Employee_id=em.Employee_id and Idate like @month) Late_Comming_Days   ,
( select count(IsPaidLeave) from HR_LeaveRequest_DateWise lr join HR_LeaveTypes lt  on lr.LeaveTypeId=lt.LeaveId  where lr.EmployeeId=em.Employee_Id and idate like @month and IsPaidLeave='Paid' ) Paid_Leave  , 
( select count(IsPaidLeave) from HR_LeaveRequest_DateWise lr join HR_LeaveTypes lt  on lr.LeaveTypeId=lt.LeaveId  where lr.EmployeeId=em.Employee_Id and idate like @month and IsPaidLeave='Unpaid' ) UnPaidLeave   , 
( select count(IsPaidLeave) from HR_LeaveRequest_DateWise lr join HR_LeaveTypes lt  on lr.LeaveTypeId=lt.LeaveId  where lr.EmployeeId=em.Employee_Id and idate like @month and IsPaidLeave='Half Pay' ) Half_Pay_leave    from HR_Employee_Master em) t

End");
