                        list.Add(@"Alter PROCEDURE sp_HMS_Invetory_item_Master
@Id         int=0,
@Item_id        varchar(500) =NULL,
@Brand_id       varchar(500) =NULL,
@Unit_id        varchar(500) =NULL,
@GST        varchar(500) =NULL,
@HSN        varchar(500) =NULL,
@Item_Name      nvarchar(max) =NULL,
@Created_by         varchar(500) =NULL,
@Created_Date       datetime=NULL,
@Created_idate      int=NULL,
@Updated_by         varchar(500) =NULL,
@Updated_Date       datetime=NULL,
@Updated_idate      int=NULL,
@firm  int=NULL,
@Item_type  varchar(500) =NULL,
@secondryUnit_id  varchar(500) =NULL,
@unit_conversion  varchar(500) =NULL,
@Isaddmoreunit varchar(50) =NULL,

@Brand_name varchar(500) =NULL,
@Category_id varchar(500)=null,
@Category_name varchar(500)=null,
@Sub_Category_id varchar(500)=null,
@Sub_Category_name  varchar(500)=null,
@Manufracture_id varchar(500)=null,
@Generic_id  varchar(500)=null,
@Manufracture_name  varchar(500)=null,
@Generic_name  varchar(500)=null,
@item_No varchar(500)=null,
@Group_Id varchar(500)=null,
@Color varchar(500)=null,
@Size nvarchar(max)=null,
@sp_status        VARCHAR(50)
 
AS
Begin
-----------------Insert new data----------------
if @sp_status ='INSERT'
  Begin
IF NOT EXISTS(select * from HMS_Invetory_item_Master where Item_id=@Item_id)
    BEGIN
        INSERT INTO HMS_Invetory_item_Master (Item_id,Brand_id,Unit_id,GST,HSN,Item_Name,Created_by,Created_Date,Created_idate,Item_type,Firm,Group_Id,Color,Size) values (@Item_id,@Brand_id,@Unit_id,@GST,@HSN,@Item_Name,@Created_by,@Created_Date,@Created_idate,@Item_type,@Firm,@Group_Id,@Color,@Size);
        
        if @Isaddmoreunit='Yes'
        begin
            insert into Inventory_Item_Unit_Maping(Item_Code,unit_id,parent_unit,unit_conversion,firm) values (@Item_id,@secondryUnit_id,@Unit_id,@unit_conversion,@firm);
        end
         
  
    END
  End
  -----------------Fetching data----------------
if @sp_status ='Fetch'
BEGIN
    select im.*,bm.Brand_name,um.Unit,c.Category_name,sc.Sub_Category_name,gm.Generic_name,mm.Manufracture_name,( Select top 1 Group_Name from HMS_Invetory_Group_Master where Group_Id=im.Group_Id ) as Group_Name from HMS_Invetory_item_Master im join HMS_Invetory_Brand_Master bm on im.Brand_id = bm.Brand_id join unit_master um on im.Unit_id=um.unit_id left join HMS_Invetory_Category_Master c on im.Category_id=c.Category_id left join HMS_Invetory_Sub_Category_Master sc on im.Sub_Category_id=sc.Sub_Category_id left join HMS_Invetory_Manufracture_Master mm on im.Manufracture_id=mm.Manufracture_id left join HMS_Invetory_Generic_Master gm on im.Generic_id=gm.Generic_id where um.firm=@firm order by Created_Date desc
END
-----------------Delete data----------------
if @sp_status ='DELETE'
BEGIN
Delete FROM HMS_Invetory_item_Master where Id=@Id
END
-----------------Update data----------------
 if @sp_status ='UPDATE'
Begin
    Update HMS_Invetory_item_Master set  Brand_id=@Brand_id,Unit_id=@Unit_id,GST=@GST,HSN=@HSN,Item_Name=@Item_Name,Created_idate=@Created_idate,Updated_by=@Updated_by,Updated_Date=@Updated_Date,Updated_idate=@Updated_idate,Item_type=@Item_type,Group_Id=@Group_Id,Color=@Color,Size=@Size where Item_Id = @Item_Id; 
    
       if @Isaddmoreunit='Yes'
        begin
            insert into Inventory_Item_Unit_Maping(Item_Code,unit_id,parent_unit,unit_conversion,firm) values (@Item_id,@secondryUnit_id,@Unit_id,@unit_conversion,@firm);
        end
    
    
END
  if @sp_status ='Unitconversion'
BEGIN
    select *, '1 '+primary_unit+'='+unit_conversion +' '+Unit as Description from  ( select t1.*,t2.Unit,(select top 1 Unit from unit_master where unit_id=t1.parent_unit) as primary_unit from  Inventory_Item_Unit_Maping  t1 join unit_master t2 on t1.unit_id=t2.unit_id and t1.firm=t2.firm) T  where Item_Code=@Item_Id
END  

if @sp_status='INSERTSERVICES'
 begin
         select @Category_id =Category_id from HMS_Invetory_Category_Master where Category_name=@Category_name  
         IF @Category_id IS NULL Or LEN(@Category_id) = 0
         BEGIN
               select @Category_id = (select Category_id from HMS_Global_Master)
               Update HMS_Global_Master set Category_id=@Category_id+1;
                             
               insert into HMS_Invetory_Category_Master(Category_id,Category_name) values (@Category_id,@Category_name );
         end
           
           
    
           select @Sub_Category_id=Sub_Category_id from HMS_Invetory_Sub_Category_Master where Sub_Category_name=@Sub_Category_name  
           
           IF @Sub_Category_id IS NULL Or LEN(@Sub_Category_id)= 0
         BEGIN
               select @Sub_Category_id = (select Sub_Category_id from HMS_Global_Master)
               Update HMS_Global_Master set Sub_Category_id=@Sub_Category_id+1;
                             
               insert into HMS_Invetory_Sub_Category_Master(Category_id,Sub_Category_id,Sub_Category_name) values (@Category_id,@Sub_Category_id,@Sub_Category_name );
         end
           
     select @Brand_id =Brand_id from HMS_Invetory_Brand_Master where Brand_name=@Brand_name  
    IF @Brand_id IS NULL Or LEN(@Brand_id) = 0
         BEGIN
               select @Brand_id = (select Brand_Id from HMS_Global_Master)
               Update HMS_Global_Master set Brand_Id=@Brand_id+1;
                             
               insert into HMS_Invetory_Brand_Master(Brand_id,Brand_name) values (@Brand_id,@Brand_name );
         end
    
           
             select @Manufracture_id =Manufracture_id from HMS_Invetory_Manufracture_Master where Manufracture_name=@Manufracture_name  
             IF @Manufracture_id IS NULL Or LEN(@Manufracture_id) = 0
         BEGIN
               select @Manufracture_id = (select Manufracture_id from HMS_Global_Master)
               Update HMS_Global_Master set Manufracture_id=@Manufracture_id+1;
                             
               insert into HMS_Invetory_Manufracture_Master(Manufracture_id,Manufracture_name) values (@Manufracture_id,@Manufracture_name );
         end
           
           
             select @Generic_id =Generic_id from HMS_Invetory_Generic_Master where Generic_name=@Generic_name  
             IF @Generic_id IS NULL Or LEN(@Generic_id) = 0
         BEGIN
