                        list.Add(@"Alter PROCEDURE sp_Fetch_month_dues 
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id  as varchar(500),
@Room_Category_id  as varchar(500),
@Hostel_assig_id as varchar(500),
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50),
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@TransportationPath_id  as varchar(500) ,
@Boarding_Point_id  as varchar(500) ,
@transportportation_id  as varchar(500) ,
@monthid  as int=0,
@sp_status       VARCHAR(500)
AS
Begin
    ---------Datewise Order Count----------
    
    if @hosteltaken='yes'
    
            begin
                 if @sp_status ='1'
BEGIN
    declare @applyfor as varchar(50),@parameter as varchar(50);
    set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
    
               select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter and fmc.Month=@months and fmc.parameter_id=@parameter_id and fmc.Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id
 
                 union ALL
                  select   t3.Service_amount as amount,(isnull((select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no=@admission_no and month=@months and session_id=@session_id and content_id=t2.Service_id and group_id='4' and Hostel_id=@hostel_id and parameter_id='555'),(select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no='All' and month=@months and content_id=t2.Service_id and group_id='4' and   session_id=@session_id and group_id='4' and Hostel_id=@hostel_id  and category_id=@category_id and sub_category_id=@sub_category_id and parameter_id='555'))) disc_amount from Hostel_assign_master t1 join Hostel_assigned_additional_service t2 on t1.Hostel_assign_id=t2.Assign_id join Hostel_service_master t3 on t2.Service_id=t3.Service_id where t1.Hostel_assign_id=@Hostel_assig_id
                 
                  
                    union ALL Select Amount as amount,'0.00' as disc_amount from Hostel_student_damage_Item_maping hsdi where hsdi.For_motn_name=@months and hsdi.Assign_id=@Hostel_assig_id and hsdi.Admission_no=@admission_no


UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id
UNION all
select  Amount amount,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and  Hostel_id= case when Apply_for='Both' then 0 else @hostel_id end  and ( Apply_for='Hosteller' or Apply_for='Both'))t 
 
 END 
                 
            end 
         else
            begin
                
    if @sp_status ='1'
BEGIN
    select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter='MonthlyFee' and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all
select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id ))) disc_amount from Student_mapping_with_TransportPath smt join Transportation_Fee_Master tr on smt.TransportPath_id=tr.Transportation_path_id and  smt.Boarding_Point_id=tr.Boarding_Point_id and tr.Month=@months and tr.Session_id=@session_id where  smt.Year_month<=@monthid and smt.TransportPath_id=@TransportationPath_id and smt.transport_id=@transportportation_id and smt.Boarding_Point_id=@Boarding_Point_id and smt.Admission_no=@admission_no and smt.Session_id=@session_id  and smt.Class_id=@class_id 

union all select Amount amount,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null)

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id) t 
 END
 end 







if @sp_status ='2'
BEGIN
    if @hosteltaken='yes'
    
            begin
                if @sp_status ='2'
                 BEGIN 
                 set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
    
                 select @months as Month, (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter and fmc.Month=@months and fmc.parameter_id=@parameter_id and fmc.Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id
 
UNION all


 select   t3.Service_amount as amount,(isnull((select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no=@admission_no and month=@months and session_id=@session_id and content_id=t2.Service_id and group_id='4' and Hostel_id=@hostel_id and parameter_id='555'),(select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no='All' and month=@months and content_id=t2.Service_id and group_id='4' and   session_id='2' and group_id='4' and Hostel_id=@hostel_id  and category_id=@category_id and sub_category_id=@sub_category_id and parameter_id='555'))) disc_amount from Hostel_assign_master t1 join Hostel_assigned_additional_service t2 on t1.Hostel_assign_id=t2.Assign_id join Hostel_service_master t3 on t2.Service_id=t3.Service_id where t1.Hostel_assign_id=@Hostel_assig_id




UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id

union all select Amount amount,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null)

) t 
 END 
                 
            end 
         else
            begin
                
                if @sp_status ='2'
BEGIN
    select @months as Month,(sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select fmc.amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter='MonthlyFee' and fmc.Month=@months and fmc.parameter_id=@parameter_id
 
UNION all

select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id ))) disc_amount  from Student_mapping_with_TransportPath smt join Transportation_Fee_Master tr on smt.TransportPath_id=tr.Transportation_path_id and  smt.Boarding_Point_id=tr.Boarding_Point_id and tr.Month=@months and tr.Session_id=@session_id where  smt.Year_month<=@monthid and smt.TransportPath_id=@TransportationPath_id and smt.transport_id=@transportportation_id and smt.Boarding_Point_id=@Boarding_Point_id and smt.Admission_no=@admission_no and smt.Session_id=@session_id  and smt.Class_id=@class_id 

UNION all
select Amount amount,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id
union all select Amount amount,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null)

) t 
 END
 end 

 END

End");
                        list.Add(@"create PROCEDURE sp_Fetch_transport_dues 
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id  as varchar(500),
@Room_Category_id  as varchar(500),
@Hostel_assig_id as varchar(500),
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50),
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@TransportationPath_id  as varchar(500) ,
@Boarding_Point_id  as varchar(500) ,
@transportportation_id  as varchar(500) ,
@monthid  as int=0,
@sp_status       VARCHAR(500)
AS
begin
    if @sp_status ='1'
    BEGIN
    select (sum(convert(float, amount))-sum(convert(float, isnull((disc_amount),'0')))) as Total_Dues from (select tr.Amount as amount,(isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id ))) disc_amount from Student_mapping_with_TransportPath smt join Transportation_Fee_Master tr on smt.TransportPath_id=tr.Transportation_path_id and  smt.Boarding_Point_id=tr.Boarding_Point_id and tr.Month=@months and tr.Session_id=@session_id where  smt.Year_month<=@monthid and smt.TransportPath_id=@TransportationPath_id and smt.transport_id=@transportportation_id and smt.Boarding_Point_id=@Boarding_Point_id and smt.Admission_no=@admission_no and smt.Session_id=@session_id  and smt.Class_id=@class_id) t
End
End");


                        list.Add(@"Alter PROCEDURE sp_update_admission_no_and_Class
 @admissionserialnumber_old       varchar(500) =NULL,
@admissionserialnumber       varchar(500) =NULL,
@Session_id         varchar(500) =NULL,
@updated_by         varchar(500) =NULL,
@updated_date       varchar(500) =NULL,
@session varchar(500) =NULL,
@Class_id varchar(500) =NULL,
@slip_no varchar(500) =NULL,
@rollno_old varchar(500) =NULL,
@Roll_no_New varchar(500) =NULL,
@Class_idnew varchar(500) =NULL,
@Class_name varchar(500) =NULL,
@Old_section varchar(500) =NULL,
@New_Section varchar(500) =NULL,

@Branch_id varchar(500) =NULL,
@status        VARCHAR(5000)
 
AS
Begin 

            ----Insert new data----

            if @status ='updateadmissionno'
             Begin  
        
                 update admission_registor set admissionserialnumber=@admissionserialnumber where admissionserialnumber=@admissionserialnumber_old and Session_id=@Session_id
                 
                 INSERT INTO admission_registor_Change_admission_no_history (Old_admission_no,Current_admission_no,Session_id,Created_By,Date_time,Change_type,Branch_id) values (@admissionserialnumber_old,@admissionserialnumber,@Session_id,@updated_by,@updated_date,'Admission No. Change',@Branch_id)
                 
                 update Student_mapping_with_boarding_with_lunch set Admission_no=@admissionserialnumber where Session_id=@Session_id and Admission_no=@admissionserialnumber_old
                 update Admission_fee_collection set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                 update Annual_fee_collection set  Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                  update Admission_fee_collection set  Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and session=@session
                 
                 
                 update Discount_Master set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session_id=@Session_id
                 
                 update Discount_Master_for_bus set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session_id=@Session_id
                 
                 update Discount_Master_Monthly_Studentwise set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update Fine_Fees_collection set Admission_no=@admissionserialnumber where  Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update lib_student_transaction_details set student_id=@admissionserialnumber where student_id=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update Monthly_Fee_Collection_Slip set adno=@admissionserialnumber where adno=@admissionserialnumber_old and session=@session
                 
                 update Payment_transaction_process set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
                 update SchoolLedger set Addmission_no=@admissionserialnumber where  Addmission_no=@admissionserialnumber_old and session=@session
                 
                  update Student_Payment_History set Addmission_no=@admissionserialnumber where Addmission_no=@admissionserialnumber_old and Session=@session
                  
                
                 
                  update Typewise_fee_collection set admission_no=@admissionserialnumber where admission_no=@admissionserialnumber_old and session=@session 
                 
                 update Student_mapping_with_TransportPath set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id 
                 
                 update Misc_Fee_Master_Studentwise set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id 
                 
                  update Hostel_assign_master set  Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id 
                 
                 ------------------LMS----------
                 update Zoom_Meeting_Joining_Status set User_id=@admissionserialnumber where User_id=@admissionserialnumber_old and Session_id=@Session_id
                 update user_test_total_marks_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and Session_Id=@Session_id
                 
                 update user_test_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and  Session_id=@Session_id
                 update user_test_attempted_details set Studentid=@admissionserialnumber where Studentid=@admissionserialnumber_old and  Session_id=@Session_id
                 
                 update Subjective_particpation set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_id=@Session_id
                 
                 update Subjective_Pdf_Answer set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                 
                  update Subjective_marks_chart set Studnet_Id=@admissionserialnumber where Studnet_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                  
                  update Subjective_answer set Student_Id=@admissionserialnumber where Student_Id=@admissionserialnumber_old and  Session_Id=@Session_id
                  
                   update Subject_Mapping_New set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                   
                   update Student_Remarks_Entry set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id
                   
                   
                   update Student_Practical_Viva_Marks set Admission_No=@admissionserialnumber where Admission_No=@admissionserialnumber_old and Session_id=@Session_id
                   
                   
                   update Student_Attendance_saved_Class_Wise set Admission_no=@admissionserialnumber where Admission_no=@admissionserialnumber_old and Session_id=@Session_id
                 
              End
               else  if @status ='updateclass'
                Begin  
                 
                    INSERT INTO Student_Payment_History_Save_bakup (Addmission_no,Session,Date,Idate,Description,Entry_id,Slip_no,Amount,Type,mode,discount,Discoun_in_School,Discoun_in_Hostel,Discoun_in_Transport,fine,is_ofline_sync,Is_online_sync,is_update_in_online,Previous_admission_no,App_Transection_id,time,user_id,Acamedic_Semester_Id,Branch,Class_id,User_Slip_no,Pay_mode_transaction_no,Money_Receipt_Date,Money_Receipt_Idate,Unique_id,Adjust_type,Remarks,Transection_in,insert_time_date,Insert_time_user_id,New_Slip_no)
                    SELECT Addmission_no,Session,Date,Idate,Description,Entry_id,Slip_no,Amount,Type,mode,discount,Discoun_in_School,Discoun_in_Hostel,Discoun_in_Transport,fine,is_ofline_sync,Is_online_sync,is_update_in_online,Previous_admission_no,App_Transection_id,time,user_id,Acamedic_Semester_Id,Branch,Class_id,User_Slip_no,Pay_mode_transaction_no,Money_Receipt_Date,Money_Receipt_Idate,Unique_id,Adjust_type,Remarks,Transection_in,@updated_date,@updated_by,@slip_no
                 FROM Student_Payment_History where Addmission_no=@admissionserialnumber and Session=@session and Class_id=@Class_id
                 
                 
                 update admission_registor set admissionserialnumber=@admissionserialnumber,rollnumber=@Roll_no_New,Section=@New_Section,class=@Class_name,Class_id=@Class_idnew,payment_status='Unpaid'    where admissionserialnumber=@admissionserialnumber_old and Session_id=@Session_id 
                 
                 
                 update Student_mapping_with_TransportPath set  Class_id=@Class_idnew where Admission_no=@admissionserialnumber_old and Session_id=@Session_id 
                 
                 
                 update Hostel_assign_master set  Class_id=@Class_idnew where Admission_no=@admissionserialnumber_old and Session_id=@Session_id 
                  
                  
                  
                 INSERT INTO admission_registor_Change_admission_no_history (Old_admission_no,Current_admission_no,Session_id,Created_By,Date_time,Change_type,Old_Class_id,Class_Id_New,Roll_no_old,Roll_no_New,Slip_no,Old_Section_name,New_Section,Branch_id) values (@admissionserialnumber_old,@admissionserialnumber,@Session_id,@updated_by,@updated_date,'Class Name Change',@Class_id,@Class_idnew,@rollno_old,@Roll_no_New,@slip_no,@Old_section,@New_Section,@Branch_id)
                   
                   
                 ---------------delete from payment history---------------
                 
                 delete from Admission_fee_collection where Admission_no=@admissionserialnumber and session=@session
                 delete from Annual_fee_collection  where Admission_no=@admissionserialnumber and session=@session
                 delete Student_mapping_with_boarding_with_lunch   where Session_id=@Session_id and Admission_no=@admissionserialnumber
                 
                   delete Discount_Master  where admission_no=@admissionserialnumber and session_id=@Session_id
                 
                   delete Discount_Master_for_bus   where admission_no=@admissionserialnumber and session_id=@Session_id
                 
                   delete Discount_Master_Monthly_Studentwise   where Admission_no=@admissionserialnumber and Session_id=@Session_id
                   delete Fine_Fees_collection   where  Admission_no=@admissionserialnumber and Session_id=@Session_id
                   
                    delete Monthly_Fee_Collection_Slip   where adno=@admissionserialnumber and session=@session
                 
                    delete Payment_transaction_process   where Admission_no=@admissionserialnumber and Session_id=@Session_id
                 
                    delete SchoolLedger  where  Addmission_no=@admissionserialnumber and session=@session
                 
                    delete Student_Payment_History  where Addmission_no=@admissionserialnumber and Session=@session
                  
                
                 
                    delete Typewise_fee_collection   where admission_no=@admissionserialnumber and session=@session
                   
                   
                   
                   
                   
                End
    

End");
                        list.Add(@"Alter proc sp_fetch_monthly_fee
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id  as varchar(500),
@Room_Category_id  as varchar(500),
@Hostel_assig_id as varchar(500),
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50),
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@monthid  as int=0,
@TransportationPath_id  as varchar(500),
@Boarding_Point_id  as varchar(500),
@transportportation_id  as varchar(500)
as 
begin 
    declare @applyfor as varchar(50),@parameter as varchar(50);
  
        if @hosteltaken='yes'
            begin
                 set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
                 select '0'id,@admission_no admission_no,@class class,@session session,parameter,content,amount,'0',amount,'Dues',@months months,content_id,Ledger,0,0,0,disc_amount from (  select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months and fmc.Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id
                 
                 union ALL
                  select   t3.Service_name as content,t2.Service_id as content_id,t3.Service_amount as amount,'AdditionalServices' as parameter,'' as Ledger,(isnull((select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no=@admission_no and month=@months and session_id=@session_id and content_id=t2.Service_id and group_id='4' and Hostel_id=@hostel_id and parameter_id='555'),(select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no='All' and month=@months and content_id=t2.Service_id and group_id='4' and   session_id='2' and group_id='4' and Hostel_id=@hostel_id  and category_id=@category_id and sub_category_id=@sub_category_id and parameter_id='555'))) disc_amount from Hostel_assign_master t1 join Hostel_assigned_additional_service t2 on t1.Hostel_assign_id=t2.Assign_id join Hostel_service_master t3 on t2.Service_id=t3.Service_id where t1.Hostel_assign_id=@Hostel_assig_id
                 
                  
                    union ALL Select (Select top 1 Item_name+','+'(DamageCharges)' from  Hostel_Damage_Item_master where Item_id=hsdi.Damage_goods_item_id ) as Perticular,Damage_goods_item_id as content_id,Amount as amount,'DamageCharges' as parameter,'' as Ledger,'0.00' as disc_amount from Hostel_student_damage_Item_maping hsdi where hsdi.For_motn_name=@months and hsdi.Assign_id=@Hostel_assig_id and hsdi.Admission_no=@admission_no
                  
                   union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0.00' disc_amount  from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id  
                   union 
               all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0.00' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and Hostel_id= case when Apply_for='Both' then 0 else @hostel_id end  and ( Apply_for=@applyfor or Apply_for='Both'))t; 
            end 
         else
            begin
                set @applyfor='Day Scholar';
                 set @parameter='MonthlyFee'; 
                 --set @parameter_id='4'; 
                 select '0'id, @admission_no admission_no,@class class,@session session,parameter,content,amount,'0',amount,'Dues',@months months,content_id,Ledger,0,0,0,disc_amount from ( 
                 
                 select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,(isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months and fmc.parameter_id=@parameter_id 
                 
                 union all select 'TransportationFee' as content,tr.parameter_id as content_id,tr.Amount as amount,@parameter parameter,tr.Ledger, (isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id ))) disc_amount
                 from Student_mapping_with_TransportPath smt join Transportation_Fee_Master tr on smt.TransportPath_id=tr.Transportation_path_id and  smt.Boarding_Point_id=tr.Boarding_Point_id and tr.Month=@months and tr.Session_id=@session_id where  smt.Year_month<=@monthid and smt.TransportPath_id=@TransportationPath_id and smt.transport_id=@transportportation_id and smt.Boarding_Point_id=@Boarding_Point_id and smt.Admission_no=@admission_no and smt.Session_id=@session_id and smt.Class_id=@class_id 
                 
                 union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id 
                 
                 union all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null))t;
          end
end");


