                        list.Add(@"CREATE PROCEDURE sp_payment_Voucher_Details
 @firm                   varchar(200) =NULL, 
 @Session                varchar(200) =NULL, 
 @VoucherType           varchar(200) =NULL, 
 @unique_entry_id  varchar(500) =NULL, 
 @sp_status              int
 
AS
Begin
    
-----------------Insert new data----------------
if @sp_status =1
  Begin
      select  Account_Name as DataTextField ,Account_id as DataValueField from dbo.[Account_Ledger_Details] where Group_id in('27','28') and firm=@firm
  End
   
if @sp_status =2
  Begin
       select  Account_Name as DataTextField ,Account_id as DataValueField from dbo.[Account_Ledger_Details] where Group_id in('13','15') and firm=@firm
  End
   if @sp_status =3
  Begin
      select VoucherNo,Date,IDate,sum(cast(Credit as float)) Credit ,sum(cast(Debit as float)) Debit,unique_entry_id,ref_name from dbo.[Account_Voucher_Details]   where  VoucherType=@VoucherType  and firm =@firm and Bill_from='SCHOOL' group by VoucherNo,Date,IDate ,idate,unique_entry_id,ref_name order by idate desc
  End
   if @sp_status =4
  Begin
      
       select ld.Debit as Credit,ld.Account_id,ld.unique_entry_id,ld.Description,ld.Date,ad.Account_Name,ad.Account_id from dbo.[Account_Voucher_Details] as ld  join Account_Ledger_Details as ad on ld.Account_id=ad.Account_id and ad.firm=@firm where   ld.unique_entry_id=@unique_entry_id  and ld.Credit='0' 
       
       select ld.Account_id,ld.Credit,ad.Account_Name,Description from dbo.[Account_Voucher_Details] as ld  join Account_Ledger_Details as ad on ld.Account_id=ad.Account_id and ad.firm=@firm where   ld.unique_entry_id=@unique_entry_id  and ld.Credit!='0' 
       
  End
END");
                        list.Add(@"CREATE   PROCEDURE sp_Account_Voucher_Details
@Main_account_id      varchar(500)=NULL,
@Alternet_account_id       varchar(500)=NULL,
@Description            varchar(500) =NULL,
@Amount                 varchar(20) =NULL,
@Date                   varchar(20) =NULL, 
@IDate                  int=NULL,
@unique_entry_id        varchar(500) =NULL, 
@VoucherNo              varchar(20) =NULL, 
@VoucherType            varchar(20) =NULL, 
@firm                   varchar(200) =NULL, 
@Session                varchar(200) =NULL, 
@sp_status              VARCHAR(50),
@cash_payment float=NULL, 
@bank_payment float=NULL,
@Bill_from                   varchar(50) =NULL, 
@Created_by                varchar(50) =NULL,
@VoucherNo_Manual  varchar(200) =NULL, 
@bank_account varchar(20) =NULL
AS
Begin
    
-----------------Insert new data----------------
if @sp_status ='INSERT'
  Begin
       
      
      declare @Group_id   VARCHAR(50);
       declare @Desc   VARCHAR(500);
       
       
       --select @Main_account_id = (select Account_id from Account_Ledger_Details where Account_Name=@Main_account_name and firm=@firm)
      
       select @Group_id   = (select Group_id from Account_Ledger_Details where Account_id=@Main_account_id  and firm=@firm)
       
       --select @Alternet_account_id = (select Account_id from Account_Ledger_Details where Account_Name=@Alternet_Account  and firm=@firm)
       
       
    IF (@Alternet_account_id IS NOT NULL) OR (LEN(@Alternet_account_id) > 0) 
    BEGIN
        INSERT INTO Account_Voucher_Details  (Account_id,Description,Credit,Debit,Date,IDate,Group_id,unique_entry_id,VoucherNo,VoucherType,firm,Session,Alternet_Account,Bill_from,Created_by,VoucherNo_Manual) values (@Main_account_id,@Description,'0',@Amount,@Date,@IDate,@Group_id,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Alternet_account_id,@Bill_from,@Created_by,@VoucherNo_Manual); 
  
        select @Group_id   = (select Group_id from Account_Ledger_Details where Account_id=@Alternet_account_id   and firm=@firm)
        
        INSERT INTO Account_Voucher_Details  (Account_id,Description,Credit,Debit,Date,IDate,Group_id,unique_entry_id,VoucherNo,VoucherType,firm,Session,Alternet_Account,Bill_from,Created_by,VoucherNo_Manual) values (@Alternet_account_id,@Description,@Amount,'0',@Date,@IDate,@Group_id,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Main_account_id,@Bill_from,@Created_by,@VoucherNo_Manual); 
   
  
      if @cash_payment >0
   Begin
       set @Desc=@Description;
       set @Amount = @cash_payment;
       exec sp_cash_payment_Voucher_Details @Main_account_id,'Cash',@Desc,@Amount,@Date,@IDate,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Bill_from,@Created_by ,@sp_status 

  End
   
   if @bank_payment >0
   Begin
       set @Desc=@Description;
       set @Amount = @bank_payment;
       exec sp_bank_payment_Voucher_Details @Main_account_id,@Alternet_account_id,@Desc,@Amount,@Date,@IDate,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Bill_from,@Created_by ,@sp_status 

   End
   
End
  End

-----------------delete data----------------
if @sp_status ='DELETE'
  Begin
      --select @Alternet_account_id = (select Account_id from Account_Ledger_Details where Account_Name=@Alternet_Account  and firm=@firm)
        
        delete from dbo.[Account_Voucher_Details] where unique_entry_id=@unique_entry_id   and Alternet_Account=@Alternet_account_id
       delete from dbo.[Account_Voucher_Details] where unique_entry_id=@unique_entry_id   and Account_id=@Alternet_account_id
     
   
  End

-----------------Update data----------------
if @sp_status ='STEPDOWNUPUPDATE'
  Begin
       
      update   dbo.[Account_Voucher_Details] set Debit=@Amount where unique_entry_id=@unique_entry_id and Credit=0
      update   dbo.[Account_Voucher_Details] set Credit=@Amount where unique_entry_id=@unique_entry_id and Debit=0
      
     
   
  End

  
  if @sp_status ='UPDATE'
  Begin 
      --select @Main_account_id = (select Account_id from Account_Ledger_Details where Account_Name=@Main_account_name   and firm=@firm)
      
      select @Group_id   = (select Group_id from Account_Ledger_Details where Account_id=@Main_account_id   and firm=@firm)
       
      --select @Alternet_account_id = (select Account_id from Account_Ledger_Details where Account_Name=@Alternet_Account   and firm=@firm)
      
    IF (@Alternet_account_id IS NOT NULL) OR (LEN(@Alternet_account_id) > 0)
 
    BEGIN
        
        update Account_Voucher_Details set Debit=@Amount,Date=@Date,IDate=@IDate where Account_id=@Main_account_id and unique_entry_id=@unique_entry_id and Alternet_Account=@Alternet_account_id;
       
       update Account_Voucher_Details set Credit=@Amount,Date=@Date,IDate=@IDate where Account_id=@Alternet_account_id and unique_entry_id=@unique_entry_id and Alternet_Account=@Main_account_id;
        
End
  End

  
END");
                        list.Add(@"CREATE   PROCEDURE sp_bank_payment_Voucher_Details
