      INSERT INTO Account_Voucher_Details_bc  (Account_id,Description,Credit,Debit,Date,IDate,Group_id,unique_entry_id,VoucherNo,VoucherType,firm,Session,Alternet_Account,Bill_from,Created_by,ref_name,VoucherNo_Manual) values (@Main_account_id,@Description,@Amount,'0',@Date,@IDate,@Group_id,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Alternet_account_id,@Bill_from,@Created_by,@ref_name,@VoucherNo_Manual); 
  
        select @Group_id   = (select Group_id from Account_Ledger_Details where Account_id=@Alternet_account_id and firm=@firm)
        
        INSERT INTO Account_Voucher_Details  (Account_id,Description,Credit,Debit,Date,IDate,Group_id,unique_entry_id,VoucherNo,VoucherType,firm,Session,Alternet_Account,Bill_from,Created_by,ref_name,VoucherNo_Manual) values (@Alternet_account_id,@Description,'0',@Amount,@Date,@IDate,@Group_id,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Main_account_id,@Bill_from,@Created_by,@ref_name,@VoucherNo_Manual); 
      
        INSERT INTO Account_Voucher_Details_bc  (Account_id,Description,Credit,Debit,Date,IDate,Group_id,unique_entry_id,VoucherNo,VoucherType,firm,Session,Alternet_Account,Bill_from,Created_by,ref_name,VoucherNo_Manual) values (@Alternet_account_id,@Description,'0',@Amount,@Date,@IDate,@Group_id,@unique_entry_id,@VoucherNo,@VoucherType,@firm,@Session,@Main_account_id,@Bill_from,@Created_by,@ref_name,@VoucherNo_Manual); 
       
   
   
      
  End

END
");
