                        list.Add(@"CREATE PROCEDURE sp_fetch_dues_of_student  
@admission_no as varchar(50),
@session_id as int,
@tr_ledger as varchar(50),
@class as varchar(50),
@session as varchar(50),
@months as varchar(500),
@class_id as int,
@hostel_id  as varchar(500),
@Room_Category_id  as varchar(500),
@Hostel_assig_id as varchar(500),
@day_boarding as bit,
@day_boarding_lunch as bit,
@hosteltaken as varchar(50),
@category_id as varchar(50),
@sub_category_id as varchar(50),
@parameter_id as varchar(50),
@monthid  as int=0,
@TransportationPath_id  as varchar(500),
@Boarding_Point_id  as varchar(500),
@transportportation_id  as varchar(500),
@Month_position  as int=0,
@Month_id  as int=0,
@Updated_date  as varchar(500),
@Updated_time  as varchar(500)
as 
begin 
    declare @applyfor as varchar(50),@parameter as varchar(50);
  
        if @hosteltaken='yes'
            begin
                 set @applyfor='Hosteller';
                 set @parameter='HostelMonthlyFee'; 
                 set @parameter_id='3'; 
                 select '0' as Id,@admission_no admission_no,@class_id Class_id, @session_id Session_id,parameter,@months months,content,content_id,amount,disc_amount,'0' Prev_paid,(convert(float, amount)-convert(float, disc_amount)) as Dues_amt,@Month_position as Month_position,@Month_id as Month_id,@Updated_date as Updated_date,@Updated_time as Updated_time from (  select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,isnull((isnull((select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id and Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))),0) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months and fmc.Hostel_id=@hostel_id and Room_Category_id=@Room_Category_id
                 
                 union ALL
                 select   t3.Service_name as content,t2.Service_id as content_id,t3.Service_amount as amount,'AdditionalServices' as parameter,'' as Ledger,isnull((isnull((select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no=@admission_no and month=@months and session_id=@session_id and content_id=t2.Service_id and group_id='4' and Hostel_id=@hostel_id and parameter_id='555'),(select top 1 disc_amount from dbo.[Hostel_Discount_Master] where admission_no='All' and month=@months and content_id=t2.Service_id and group_id='4' and   session_id='2' and group_id='4' and Hostel_id=@hostel_id  and category_id=@category_id and sub_category_id=@sub_category_id and parameter_id='555'))),0) disc_amount from Hostel_assign_master t1 join Hostel_assigned_additional_service t2 on t1.Hostel_assign_id=t2.Assign_id join Hostel_service_master t3 on t2.Service_id=t3.Service_id where t1.Hostel_assign_id=@Hostel_assig_id
                 
                  
                    union ALL Select (Select top 1 Item_name+','+'(DamageCharges)' from  Hostel_Damage_Item_master where Item_id=hsdi.Damage_goods_item_id ) as Perticular,Damage_goods_item_id as content_id,Amount as amount,'DamageCharges' as parameter,'' as Ledger,'0.00' as disc_amount from Hostel_student_damage_Item_maping hsdi where hsdi.For_motn_name=@months and hsdi.Assign_id=@Hostel_assig_id and hsdi.Admission_no=@admission_no
                  
                   union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0.00' disc_amount  from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id  
                   union 
               all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0.00' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and Hostel_id= case when Apply_for='Both' then 0 else @hostel_id end  and ( Apply_for=@applyfor or Apply_for='Both'))t; 
            end 
         else
            begin
                set @applyfor='Day Scholar';
                 set @parameter='MonthlyFee'; 
                 --set @parameter_id='4'; 
                 select  '0' as Id,@admission_no admission_no,@class_id Class_id, @session_id Session_id,parameter,@months months,content,content_id,amount,disc_amount,'0' Prev_paid,(convert(float, amount)-convert(float, disc_amount)) as Dues_amt,@Month_position as Month_position,@Month_id as Month_id,@Updated_date as Updated_date,@Updated_time as Updated_time from ( 
                 
                 select cm.content,fmc.content_id,fmc.amount,fmc.parameter,fmc.Ledger,isnull((isnull((select top 1 disc_amount from dbo.[Discount_Master] where admission_no=@admission_no and month=@months  and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id),(select top 1 disc_amount from dbo.[Discount_Master] where Class_id=@class_id and admission_no='All' and month=@months and parameter_id=@parameter_id and session=@session and fee_head_id=fmc.content_id and category_id=@category_id AND sub_category_id=@sub_category_id))),0) disc_amount from dbo.[Fee_master_content_wise] fmc join Content_master cm on fmc.content_id=cm.content_id where fmc.session_id=@session_id and fmc.class_id=@class_id and fmc.parameter=@parameter  and fmc.Month=@months and fmc.parameter_id=@parameter_id 
                 
                 union all select 'TransportationFee' as content,tr.parameter_id as content_id,tr.Amount as amount,@parameter parameter,tr.Ledger, isnull((isnull((select top 1 disc_amount from dbo.[Discount_Master_for_bus] where admission_no=@admission_no and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id),(select top 1 disc_amount from dbo.[Discount_Master_for_bus] where  admission_no='All' and month=@months and session_id=@session_id and TransportationPath_id=@TransportationPath_id and Transportation_Id=@transportportation_id and Boarding_Point_id=@Boarding_Point_id ))),0) disc_amount
                 from Student_mapping_with_TransportPath smt join Transportation_Fee_Master tr on smt.TransportPath_id=tr.Transportation_path_id and  smt.Boarding_Point_id=tr.Boarding_Point_id and tr.Month=@months and tr.Session_id=@session_id where  smt.Year_month<=@monthid and smt.TransportPath_id=@TransportationPath_id and smt.transport_id=@transportportation_id and smt.Boarding_Point_id=@Boarding_Point_id and smt.Admission_no=@admission_no and smt.Session_id=@session_id and smt.Class_id=@class_id 
                 
                 union ALL select Perticular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount from Misc_Fee_Master_Studentwise where Admission_No=@admission_no and  Month=@months and session_id=@session_id 
                 
                 union all select Particular content,'1001' content_id,Amount amount,@parameter parameter,Ledger,'0' disc_amount  from Miscellaneous_Fee_Master where Month=@months and session_id=@session_id and class_id=@class_id  and ( Apply_for=@applyfor or Apply_for='Both')  and (day_boarding_with_lunch=@day_boarding_lunch or  day_boarding_with_lunch is null) and ( day_boarding=@day_boarding or day_boarding is null))t;
          end
end");

