                        list.Add(@"create PROCEDURE sp_Daily_Collection_Report
 @fromdate int= null,
 @todate int= null,
 @status2  VARCHAR(5000),
 @sessionid  VARCHAR(5000),
 @sessionname  VARCHAR(5000),
 @endidate  VARCHAR(5000)= null,
 @status        VARCHAR(5000)
 
AS
Begin 

            ----Insert new data----

if @status ='Daily_Collection'
 Begin 
     if @status2 ='Student_payment'
    Begin  
        
        
        Select Addmission_no,Session,Date,Slip_no,Type,mode,Bank_name,Amount,(Select top 1 studentname from  admission_registor where admissionserialnumber=sph.Addmission_no) as studentname,(select top 1 name from user_details where user_id=sph.user_id) username from Student_Payment_History sph where Idate >= @fromdate and Idate <= @todate and Session=@sessionname order by Idate asc
    End
  
    else if @status2 ='Student_payment_group'
    Begin  
        
        
        Select  sph.mode,sum(cast(sph.Amount as float) ) as totalamount from Student_Payment_History sph where sph.Idate >=@fromdate and sph.Idate <= @todate and Session=@sessionname group by sph.mode order by sph.mode
    End
 
    else if @status2 ='Student_form_sale'
    Begin  
        
        
        Select sph.form_indesx_no as Form_no ,sph.session,sph.date,sph.recpt_no,'Form Sale' as Type,sph.Payment_Mode,sph.Bank_name,sph.Amount,sph.student_name,(select top 1 name from user_details where user_id=sph.Created_by) username from Form_sale_details sph where idate >= @fromdate and idate <= @todate and session=@sessionname order by sph.idate  asc
    End
  
    else if @status2 ='Student_form_sale_group'
    Begin  
        
        
        Select  sph.Payment_Mode,sum(cast(sph.Amount as float) ) as totalamount from Form_sale_details sph where sph.Idate >=@fromdate and sph.Idate <= @todate and session=@sessionname  group by sph.Payment_Mode order by sph.Payment_Mode
    End
 
    else if @status2 ='Student_other_fee'
    Begin  
        
        
        Select sph.Admission_no,sph.Payment_date,sph.Slipid,'Other Fee' as type ,sph.Payment_mode,sph.Bank_name,sph.Content_Fee,(Select top 1 studentname from  admission_registor where admissionserialnumber=sph.Admission_no) as studentname,(select top 1 name from user_details where user_id=sph.Created_by) username from Other_Fee_Taken_For_Student sph where sph.Payment_Idate >= @fromdate and sph.Payment_Idate <= @todate and Session_id=@sessionid order by sph.Payment_Idate  asc
    End
    else if @status2 ='Student_other_fee_group'
    Begin  
        
        
        Select  sph.Payment_mode,sum(cast(sph.Content_Fee as float) ) as totalamount from Other_Fee_Taken_For_Student sph where sph.Payment_Idate >=@fromdate and sph.Payment_Idate <= @todate and Session_id=@sessionid  group by sph.Payment_mode 
    End
 
    else if @status2 ='PaymentVoucher'
    Begin  
        select Created_by,VoucherNo_Manual as VoucherNo,Description,sum(cast(Credit as float)) Credit ,sum(cast(Debit as float)) Debit,unique_entry_id,ref_name,(Substring (Date,1,2)+'/'+Substring (Date,4,2)+'/'+Substring (Date,7,5)) as date_one  from dbo.[Account_Voucher_Details]   where  VoucherType='Payment' and firm ='1' and  Bill_from='SCHOOL'  and IDate>=@fromdate and  IDate<=@todate and Session=@sessionname   group by VoucherNo_Manual,Date ,idate,unique_entry_id,ref_name,Description,Created_by   order by idate asc
 
End
      else if @status2 ='PaymentVoucherfee_group'
    Begin  
        Select *,(Select top 1 Account_Name from Account_Ledger_Details where Account_id=t.Account_id ) as accountname from (select  Account_id,sum(cast(Credit as float)) Debit     from dbo.[Account_Voucher_Details]   where  VoucherType='Payment' and firm ='1' and  Bill_from='SCHOOL'  and IDate>=@fromdate and  IDate<=@todate and Session=@sessionname and CONVERT( float, Credit)>0   group by  Account_id) t
    
    End
  
  
   else if @status2 ='ReceiptVoucher'
    Begin  
        select Created_by,VoucherNo_Manual as VoucherNo,Description,sum(cast(Credit as float)) Credit ,sum(cast(Debit as float)) Debit,unique_entry_id,ref_name,(Substring (Date,1,2)+'/'+Substring (Date,4,2)+'/'+Substring (Date,7,5)) as date_one  from dbo.[Account_Voucher_Details]   where  VoucherType='Receipt' and firm ='1' and  Bill_from='SCHOOL'  and IDate>=@fromdate and  IDate<=@todate and Session=@sessionname   group by VoucherNo_Manual,Date ,idate,unique_entry_id,ref_name,Description,Created_by   order by idate asc
 
End
      else if @status2 ='ReceiptVoucherfee_group'
    Begin  
        Select *,(Select top 1 Account_Name from Account_Ledger_Details where Account_id=t.Account_id ) as accountname from (select  Account_id,sum(cast(Debit as float)) Debit     from dbo.[Account_Voucher_Details]   where  VoucherType='Receipt' and firm ='1' and  Bill_from='SCHOOL'  and IDate>=@fromdate and  IDate<=@todate and Session=@sessionname and CONVERT( float, Debit)>0   group by  Account_id) t
    
    End
  
    
    else if(@status2  ='openingBalance_cash')
    BEGIN
        
         declare  @totalstudentfee decimal(18,2)
          declare  @totalstudentform decimal(18,2)
            declare  @totalstudentother decimal(18,2)
         declare  @totalReceipt decimal(18,2)
         declare  @totalPayment decimal(18,2)
          declare  @opening_Balance decimal(18,2)
         
          set @totalstudentfee=( Select   isnull(sum(cast(sph.Amount as float) ),0) as totalamount from Student_Payment_History sph where   sph.Idate < @fromdate and Session=@sessionname  and  mode='Cash')
          
          
          set @totalstudentform=( Select  isnull(sum(cast(sph.Amount as float) ),0) as totalamount from Form_sale_details sph where    sph.Idate <@fromdate and   sph.Idate>=@endidate and Session=@sessionname and sph.Payment_Mode='Cash'  )
         
         
            
          set @totalstudentother=(  Select  isnull(sum(cast(sph.Content_Fee as float) ),0) as totalamount from Other_Fee_Taken_For_Student sph where   sph.Payment_Idate < @fromdate and Session_id=@sessionid and sph.Payment_mode='Cash'  )
              
              
         
          set @totalReceipt=(Select isnull(sum(cast( isnull(Debit,0) as float)),0)   from Account_Voucher_Details where Account_id='cash' and VoucherType='Receipt' and Bill_from='SCHOOL' and firm=1 and  IDate<@fromdate)
          
          
            set @totalPayment=(Select isnull(sum(cast( isnull(Credit,0) as float)),0)   from Account_Voucher_Details where Account_id='cash' and VoucherType='Payment' and Bill_from='SCHOOL' and firm=1 and  IDate<@fromdate)
              
              
        -- set @totalReceipt=(  Select Debit from ( Select *,(Select top 1 Account_Name from Account_Ledger_Details where Account_id=t.Account_id ) as accountname from (select  Account_id,sum(cast(Debit as float)) Debit     from dbo.[Account_Voucher_Details]   where  VoucherType='Receipt' and firm ='1' and  Bill_from='SCHOOL' and   IDate<@fromdate and Session=@sessionname  and CONVERT( float, Debit)>0   group by  Account_id) t where  Account_id='cash') t2)
              
              
              
        -- set @totalPayment=(  Select Credit from ( Select *,(Select top 1 Account_Name from Account_Ledger_Details where Account_id=t.Account_id ) as accountname from (select  Account_id,sum(cast(Credit as float)) Credit     from dbo.[Account_Voucher_Details]   where  VoucherType='Payment' and firm ='1' and  Bill_from='SCHOOL' and   IDate<@fromdate and Session=@sessionname and CONVERT( float, Credit)>0   group by  Account_id) t where  Account_id='cash')t2)
         
        
         
         set @opening_Balance =(@totalstudentfee+@totalstudentform+@totalstudentother+@totalReceipt)-@totalPayment
         
          Select  @opening_Balance
        
    END
    
      
      else if(@status2  ='openingBalance_bank')
    BEGIN
        
        declare  @totalstudentfee_bnk decimal(18,2)
          declare  @totalstudentform_bnk decimal(18,2)
            declare  @totalstudentother_bnk decimal(18,2)
         declare  @totalReceipt_bnk decimal(18,2)
         declare  @totalPayment_bnk decimal(18,2)
          declare  @opening_Balance_bnk decimal(18,2)
         
          set @totalstudentfee_bnk=( Select   isnull(sum(cast(sph.Amount as float) ),0) as totalamount from Student_Payment_History sph where   sph.Idate < @fromdate and Session=@sessionname  and  mode!='Cash')
          
          
          set @totalstudentform_bnk=( Select  isnull(sum(cast(sph.Amount as float) ),0) as totalamount from Form_sale_details sph where    sph.Idate <@fromdate and   sph.Idate>=@endidate and Session=@sessionname and sph.Payment_Mode!='Cash'  )
            
            
         set @totalstudentother_bnk=(  Select  isnull(sum(cast(sph.Content_Fee as float) ),0) as totalamount from Other_Fee_Taken_For_Student sph where   sph.Payment_Idate < @fromdate and Session_id=@sessionid  and sph.Payment_mode!='Cash'  )
              
              
              
              
       
         
         
          set @totalReceipt=(Select  isnull(sum(cast( isnull(Debit,0) as float)),0)   from Account_Voucher_Details where Account_id!='cash' and VoucherType='Receipt' and Bill_from='SCHOOL' and firm=1 and  IDate<@fromdate)
          
          
          set @totalPayment=(Select isnull(sum(cast( isnull(Credit,0) as float)),0)   from Account_Voucher_Details where Account_id!='cash' and VoucherType='Payment' and Bill_from='SCHOOL' and firm=1 and  IDate<@fromdate)
         
         
         set @opening_Balance_bnk =(@totalstudentfee_bnk+@totalstudentform_bnk+@totalstudentother_bnk+@totalReceipt_bnk)-@totalPayment_bnk
         
         
         
          Select  @opening_Balance_bnk
        
    END
      
      
      

  
  

End       ----Fetching data----
            
End");

